window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["m"]={"Michał": "<b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Marcin": "<b>Marcin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrażenia <i>Martinus</i> oznaczającego „należący do boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>”.", "Marek": "<b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Mateusz": "<b>Mateusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מַתִּתְיָהוּ&#8206;, imienia <i>Matanjah</i>, <i>Matisyahu</i> oznaczającego „dar Boga”, „dar <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”. W dawnych źródłach polskich występowało jako: <i>Mathaeus</i>, <i>Matyjasz</i>, <i>Matitiasz</i>, <i>Matyja</i>, <i>Matys(z)</i>, <i>Matoz</i>, <i>Matusz</i>. Do XVI wieku imiona <a href=\"https://pl.wikipedia.org/wiki/Maciej\" target=\"_blank\" rel=\"noopener noreferrer\">Maciej</a> i Mateusz nie były w języku polskim rozróżniane.", "Mariusz": "<b>Mariusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy rzymskiego rodu Mariuszów lub imienia boga wojny Marsa. W Polsce od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>.", "Maciej": "<b>Maciej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia hebrajskiego: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מַתִּתְיָהוּ&#8206; <i>Mattitjahu</i>, oznaczające „dar <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”.", "Marian": "<b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Mirosław": "<b>Mirosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Imię <i>Mirosław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poganie\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członów <i>Miro-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ps.</a> <i>*mirъ</i> „pokój”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">stpol.</a> <i>mir</i>, <i>mier</i> - „pokój, bezpieczeństwo, przyjaźń”) oraz <i>-sław</i> („sława”). Mogło oznaczać „ten, który sławi pokój” albo „ten, który zdobywa sławę poprzez zaprowadzenie porządku, pokoju”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Mikołaj": "<b>Mikołaj</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Νικόλαος, <i>Nikólaos</i>, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;νίκη + λαός/<i>lassos</i>, tj. „zwycięstwo” + „lud”; to samo znaczenie ma imię <a href=\"https://pl.wikipedia.org/wiki/Nikodem\" target=\"_blank\" rel=\"noopener noreferrer\">Nikodem</a> od νίκη + δήμος) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego.", "Mieczysław": "<b>Mieczysław</b> – dwuczłonowe <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które powstało najprawdopodobniej w wyniku błędnego odczytania słowiańskiego imienia złożonego <a href=\"https://pl.wikipedia.org/wiki/Miecis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Miecisław</a> (którego najstarszy zapis pochodzi z 1257).", "Maksymilian": "<b>Maksymilian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>maximus</i> oznaczającego „największy” oraz nazwiska <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a>. Żeńskie odpowiedniki tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Maksymiliana\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymiliana</a> i <a href=\"https://pl.wikipedia.org/wiki/Maksymiliana\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymilianna</a>.", "Marcel": "<b>Marceli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy jednej z gałęzi rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Klaudiuszów</a>, <i>Marcelli</i>. Imię to bywa nadawane także w formie <b>Marcel</b>, jakkolwiek pojawia się ona w wydawnictwach poprawnościowych jako nieakceptowana. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Marcela\" target=\"_blank\" rel=\"noopener noreferrer\">Marcela</a>.", "Miłosz": "<b>Miłosz</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a> oznaczające „tego, który jest miłowany”, będące pierwotnie zdrobnieniem dwuczłonowych imion takich jak: <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>. Forma Miłosz została zapisana już w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Maksym": "<b>Maksym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od przymiotnika <i>maximus</i> oznaczający \"największy\", przydomka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Istnieją liczni święci prawosławni i katoliccy o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Maksym_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wyznawca</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Grek\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Grek</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Brankowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wołoski</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Gorlicki\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Gorlicki</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_z_Riez\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym z Riez</a> i wielu innych.", "Milan": "<b>Milan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię słowiańskie</a>. Jedno z licznych <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnień od imion słowiańskich</a> zaczynających się na <i>Miło-</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>. Obecnie imię Milan używane jest także samodzielnie.", "Maria": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mieszko": "<b>Mieszko</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, najprawdopodobniej forma skrócona imienia <a href=\"https://pl.wikipedia.org/wiki/Miecis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Miecisław</a>. Imię popularne w <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">dynastii piastowskiej</a>, pierwotnie niewystępujące poza nią i nieposiadające nazewniczych równoważników słowiańskich.", "Marceli": "<b>Marceli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy jednej z gałęzi rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Klaudiuszów</a>, <i>Marcelli</i>. Imię to bywa nadawane także w formie <b>Marcel</b>, jakkolwiek pojawia się ona w wydawnictwach poprawnościowych jako nieakceptowana. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Marcela\" target=\"_blank\" rel=\"noopener noreferrer\">Marcela</a>.", "Maurycy": "<b>Maurycy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <i>Mauritius</i>. Wywodzi się od słowa oznaczającego „pochodzący z Mauretanii”, „Maur”.", "Miron": "<b>Miron</b> (<i>Myron</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>myron</i> oznaczającego „wonny olejek, pachnidło”.", "Marko": "<b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Manfred": "<b>Manfred</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów z języka staro-wysoko-niemieckiego <i>man</i> – człowiek i <i>frid</i> – opieka, pokój. Zatem Manfred to osoba „zapewniająca pokój i ochronę”.", "Manuel": "<b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Marco": "<b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Muhammad": "<b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mustafa": "<b>Mustafa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „wybrany”.", "Makary": "<b>Makary</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;μακάριος <i>makários</i> oznaczającego „szczęsny, błogosławiony”. Znaczeniowo odpowiadają mu imiona: <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a> (pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>) i <a href=\"https://pl.wikipedia.org/wiki/Szcz%C4%99sny\" target=\"_blank\" rel=\"noopener noreferrer\">Szczęsny</a>.", "Marius": "Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Md": "<b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Melchior": "Imię „Melchior” pochodzi od słowa oznaczającego „Bóg jest moją światłością”, „król światła”. Melchior wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa <i>melech</i> i oznacza króla. Imię jest przypisywane jednemu z <a href=\"https://pl.wikipedia.org/wiki/Trzej_Kr%C3%B3lowie\" target=\"_blank\" rel=\"noopener noreferrer\">trzech mędrców</a> (królów, magów) z <a href=\"https://pl.wikipedia.org/wiki/Objawienie_Pa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Nowego Testamentu</a>.", "Martyn": "<b>Marcin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrażenia <i>Martinus</i> oznaczającego „należący do boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>”.", "Medard": "<b>Medard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Powstało z członów <i>maht</i> – „potęga, władza, moc, męstwo” oraz <i>hart</i> – „silny, odważny, śmiały”.", "Modest": "<b>Modest</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>modestus, -a, -um</i> oznaczającego „umiarkowany, skromny”.", "Magnus": "<b>Magnus</b>, Magnusz – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od łac. słowa oznaczającego \"wielki\". W <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a> nosiło je szereg królów <a href=\"https://pl.wikipedia.org/wiki/Norwegia\" target=\"_blank\" rel=\"noopener noreferrer\">norweskich</a> i <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">szwedzkich</a> oraz święci.", "Miłosław": "<b>Miłosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> imię męskie, złożone z członów <i>Miło-</i> (\"miły\", \"miłujący\") i <i>-sław</i> (\"sława\"). Znaczenie imienia: \"miły sławie\". Jednym ze stosowanych zdrobnień tego imienia, obok współczesnego \"Miłek\" i staropolskiego \"Miłko\", jest <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>.", "Malik": "<b>Malik</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;ملك&#8206; <i>malik</i> „król, suweren”) – w <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indiach</a>: tytuł pochodzenia arabskiego, przyznawany osobistościom państwa <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmańskiego</a>, a także ludziom zasłużonym dla nauki. Forma żeńska brzmi <i>malika</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;ملكة&#8206;). Z czasem tytuł ten stał się <a href=\"https://pl.wikipedia.org/wiki/Nazwisko_patronimiczne\" target=\"_blank\" rel=\"noopener noreferrer\">patronimikum</a>.", "Maryan": "<b>Pinchas Burstein</b>, pseudonim <i>Maryan</i> (ur. <a href=\"https://pl.wikipedia.org/wiki/1_stycznia\" target=\"_blank\" rel=\"noopener noreferrer\">1 stycznia</a> <a href=\"https://pl.wikipedia.org/wiki/1927\" target=\"_blank\" rel=\"noopener noreferrer\">1927</a> w <a href=\"https://pl.wikipedia.org/wiki/Nowy_S%C4%85cz\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Sączu</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/15_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">15 czerwca</a> <a href=\"https://pl.wikipedia.org/wiki/1977\" target=\"_blank\" rel=\"noopener noreferrer\">1977</a> w <a href=\"https://pl.wikipedia.org/wiki/Nowy_Jork\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Jorku</a>) – polski malarz i grafik pochodzenia żydowskiego.", "Marcjan": "<b>Marcjan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#przydomek\" target=\"_blank\" rel=\"noopener noreferrer\">cognomen</a> <i>Martianus</i> (dla kobiet <i>Martiana</i>). Oznacza ono <i>należący do Marsa, poświęcony Marsowi</i>. <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościół katolicki</a> notuje wielu <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty\" target=\"_blank\" rel=\"noopener noreferrer\">świętych</a> o tym imieniu.", "Mate": "<b>Mate</b>, matero, calabaza (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszp.</a> „dynia/tykwa”) – naczynie do picia <a href=\"https://pl.wikipedia.org/wiki/Yerba_mate\" target=\"_blank\" rel=\"noopener noreferrer\">yerba mate</a>. Słowo „mate” pochodzi od słowa <i>mati</i> w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_keczua\" target=\"_blank\" rel=\"noopener noreferrer\">języka keczua</a>, oznaczającego naczynie lub pojemnik do picia; z czasem stało się nazwą naczyń do picia yerba mate. Naczynia wykonywane są z <a href=\"https://pl.wikipedia.org/wiki/Drewno_(technika)\" target=\"_blank\" rel=\"noopener noreferrer\">drewna</a> (np. <a href=\"https://pl.wikipedia.org/wiki/Gwajakowiec_lekarski\" target=\"_blank\" rel=\"noopener noreferrer\">gwajakowca lekarskiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Bursera_graveolens\" target=\"_blank\" rel=\"noopener noreferrer\">bursera graveolens</a> zwanego <i>palo santo</i>, a także z <a href=\"https://pl.wikipedia.org/wiki/Algarrobo_(drewno)\" target=\"_blank\" rel=\"noopener noreferrer\">algarrobo</a>, palo de rosa, <a href=\"https://pl.wikipedia.org/wiki/Lapacho\" target=\"_blank\" rel=\"noopener noreferrer\">lapacho</a>, drewna cytrynowego), z <a href=\"https://pl.wikipedia.org/wiki/Owoc\" target=\"_blank\" rel=\"noopener noreferrer\">owoców</a> <a href=\"https://pl.wikipedia.org/wiki/Dzbaniwo_kalebasowe\" target=\"_blank\" rel=\"noopener noreferrer\">dzbaniwa kalebasowego</a> (zwanych kalebasami lub tykwami), z metali (<a href=\"https://pl.wikipedia.org/wiki/Stal\" target=\"_blank\" rel=\"noopener noreferrer\">stal</a>, <a href=\"https://pl.wikipedia.org/wiki/Srebro\" target=\"_blank\" rel=\"noopener noreferrer\">srebro</a>) i ceramiki. Naczynia z drewna i <a href=\"https://pl.wikipedia.org/wiki/Kalabasa\" target=\"_blank\" rel=\"noopener noreferrer\">kalebasy</a> zmieniają smak <a href=\"https://pl.wikipedia.org/wiki/Napar\" target=\"_blank\" rel=\"noopener noreferrer\">naparu</a>. Nowe naczynia z kalebasy wymagają przejścia przez proces zwany <i>curado</i> (przygotowania porcji naparu w naczyniu i odstawienia na 24 godziny) w celu usunięcia resztek miąższu.", "Mirko": "<b>Mirosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Imię <i>Mirosław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poganie\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członów <i>Miro-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ps.</a> <i>*mirъ</i> „pokój”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">stpol.</a> <i>mir</i>, <i>mier</i> - „pokój, bezpieczeństwo, przyjaźń”) oraz <i>-sław</i> („sława”). Mogło oznaczać „ten, który sławi pokój” albo „ten, który zdobywa sławę poprzez zaprowadzenie porządku, pokoju”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Marcelin": "<b>Marcelin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od imienia <a href=\"https://pl.wikipedia.org/wiki/Marceli\" target=\"_blank\" rel=\"noopener noreferrer\">Marceli</a> za pomocą sufiksu oznaczającego przynależność lub pochodzenie. Istniało wielu świętych o tym imieniu.", "Mścisław": "<b>Mścisław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z dwóch członów: <i>Mści-</i> („mścić”), od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*mьstiti (sę)</i> – mścić (się), <i>*mьstь</i>/<i>*mьsta</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">stpl.</a> <i>msta</i> – zemsta, pomsta i <i>-sław</i> („sława”). Mogło oznaczać „tego, który zdobywa sławę mszcząc się na swych wrogach”.", "Maciek": "<b>Maciej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia hebrajskiego: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מַתִּתְיָהוּ&#8206; <i>Mattitjahu</i>, oznaczające „dar <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”.", "Metin": "<b>Grupa metinowa</b>, <b>metin</b> – trójwartościowa <a href=\"https://pl.wikipedia.org/wiki/Grupa_funkcyjna\" target=\"_blank\" rel=\"noopener noreferrer\">grupa funkcyjna</a> pochodząca od <a href=\"https://pl.wikipedia.org/wiki/Metan\" target=\"_blank\" rel=\"noopener noreferrer\">metanu</a>, z cząsteczki którego usunięto trzy atomy <a href=\"https://pl.wikipedia.org/wiki/Wod%C3%B3r\" target=\"_blank\" rel=\"noopener noreferrer\">wodoru</a>. W zależności od rodzaju wiązań, które tworzy z resztą cząsteczki, wyróżnić można trzy grupy:", "Mahdi": "Według niektórych koncepcji (bliższych <a href=\"https://pl.wikipedia.org/wiki/Sunnizm\" target=\"_blank\" rel=\"noopener noreferrer\">sunnizmowi</a>) jedynym mahdim był <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezus</a> – <a href=\"https://pl.wikipedia.org/wiki/Isa_(Jezus)\" target=\"_blank\" rel=\"noopener noreferrer\">Isa</a>. Częściej jednak sunnici uważają, że mahdi i Isa połączą swoje siły w ostatecznej walce z <a href=\"https://pl.wikipedia.org/wiki/Antychryst\" target=\"_blank\" rel=\"noopener noreferrer\">antychrystem</a> (fałszywym <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorokiem</a>) Dadżdżalem. Przyjście mahdiego ma poprzedzać atak wojsk niewiernych na miejscowość <a href=\"https://pl.wikipedia.org/wiki/Lod\" target=\"_blank\" rel=\"noopener noreferrer\">Lod</a> w <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izraelu</a>. Większość <a href=\"https://pl.wikipedia.org/wiki/Szyizm\" target=\"_blank\" rel=\"noopener noreferrer\">szyitów</a> uważa mahdiego za inną osobę, która ma przyjść na ziemię tuż przed <a href=\"https://pl.wikipedia.org/wiki/S%C4%85d_Ostateczny\" target=\"_blank\" rel=\"noopener noreferrer\">Sądem Ostatecznym</a>, by zbawić/uratować ludzkość przed <a href=\"https://pl.wikipedia.org/wiki/Szatan\" target=\"_blank\" rel=\"noopener noreferrer\">Szatanem</a>. Część wyznawców <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamu</a> łączy obie koncepcje, twierdząc, że Jezus urodzi się ponownie w <a href=\"https://pl.wikipedia.org/wiki/Damaszek\" target=\"_blank\" rel=\"noopener noreferrer\">Damaszku</a>, by pokonać <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">zło</a>. Według zapowiedzi Proroka <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a>, mahdi pochodzić będzie z jego rodu. Dla <a href=\"https://pl.wikipedia.org/wiki/Szyizm\" target=\"_blank\" rel=\"noopener noreferrer\">szyitów</a> jest to bardzo ważna postać, łączona czasem z osobą ostatniego ukrytego <a href=\"https://pl.wikipedia.org/wiki/Imam_(szyizm)\" target=\"_blank\" rel=\"noopener noreferrer\">imama</a>, który ma poprzedzać Mahdiego, bądź nim być.", "Miran": "W pierwszych wiekach naszej ery Miran stanowił jeden z głównych grodów królestwa Shanshan i centrum jego rolniczej części. Został odkopany w latach 1901-1903 przez <a href=\"https://pl.wikipedia.org/wiki/Aurel_Stein\" target=\"_blank\" rel=\"noopener noreferrer\">Aurela Steina</a>. W ruinach osady zachowały się liczne freski o tematyce <a href=\"https://pl.wikipedia.org/wiki/Buddyzm\" target=\"_blank\" rel=\"noopener noreferrer\">buddyjskiej</a>, zdradzające wpływy sztuki grecko-rzymskiej. Przedstawione postaci mają rzymskie lub partyjskie ubiory i rysy twarzy, zaś autor jednego z malowideł podpisał się w piśmie <a href=\"https://pl.wikipedia.org/wiki/Kharoszthi\" target=\"_blank\" rel=\"noopener noreferrer\">kharoszthi</a> imieniem <i>Tita</i> – co odczytuje się jako „Tytus”.", "Metody": "<b>Metody</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>methodos</i> – „kroczący właściwą drogą”.", "Michaił": "<b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Morten": "<b>Marcin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrażenia <i>Martinus</i> oznaczającego „należący do boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>”.", "Martinus": "<b>Marcin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrażenia <i>Martinus</i> oznaczającego „należący do boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>”.", "Mamert": "<b>Mamert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_italskie\" target=\"_blank\" rel=\"noopener noreferrer\">italskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_oskijski\" target=\"_blank\" rel=\"noopener noreferrer\">oskijskiego</a> lub sabińskiego wariantu imienia boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a> – <i>Mamers</i>, który w przypadkach zależnych (np. <i>Mamertis</i>) miał temat <i>Mamert</i>.", "Micheasz": "<b>Micheasz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i><b>מִיכַיְהוּ</b></i> — Mîkhā’iah, <i><b>מִיכָה</b></i> — Mîkhā) — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Micheasz_(autor_biblijny)\" target=\"_blank\" rel=\"noopener noreferrer\">prorok Micheasz</a>. Po hebrajsku znaczy „któż [jest taki] jak <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>?!” i stanowi synonim imienia <a href=\"https://pl.wikipedia.org/wiki/Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Michał</a>. <a href=\"https://pl.wikipedia.org/wiki/Patron_(chrze%C5%9Bcija%C5%84stwo)\" target=\"_blank\" rel=\"noopener noreferrer\">Patronem</a> tego imienia w Kościele katolickim jest <a href=\"https://pl.wikipedia.org/wiki/Micheasz_(autor_biblijny)\" target=\"_blank\" rel=\"noopener noreferrer\">prorok Micheasz</a>, autor biblijny, a w Cerkwi prawosławnej jest kilku świętych Micheaszów, m.in. Micheasz z Radoneża (<i>Michej z Radoneża</i> lub <i>Michej Radoneżski</i>), zm. <a href=\"https://pl.wikipedia.org/wiki/1385\" target=\"_blank\" rel=\"noopener noreferrer\">1385</a>, święto <a href=\"https://pl.wikipedia.org/wiki/5_maja\" target=\"_blank\" rel=\"noopener noreferrer\">5</a> lub <a href=\"https://pl.wikipedia.org/wiki/19_maja\" target=\"_blank\" rel=\"noopener noreferrer\">19 maja</a>.", "Mina": "<b>Mina</b> – imię rozmaitego pochodzenia. W niektórych kulturach posługuje się nim jako imieniem żeńskim, a w innych kulturach jest to imię męskie.", "Mika": "<b>Mika</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みか, ミカ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> i fińskie zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Michała</a>.", "Miklós": "<b>Melchior Cibinensis</b> – węgierski ksiądz katolicki piszący w I połowie <a href=\"https://pl.wikipedia.org/wiki/XVI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVI wieku</a>. Tożsamość Melchiora ciągle jest przedmiotem dyskusji. <a href=\"https://pl.wikipedia.org/wiki/Carl_Gustav_Jung\" target=\"_blank\" rel=\"noopener noreferrer\">Carl Gustav Jung</a> uważał, że chodzi tu o Nicolasa Melchiora Szebeniego, kapłana, od <a href=\"https://pl.wikipedia.org/wiki/1490\" target=\"_blank\" rel=\"noopener noreferrer\">1490</a> roku nadwornego <a href=\"https://pl.wikipedia.org/wiki/Astrologia\" target=\"_blank\" rel=\"noopener noreferrer\">astrologa</a> na dworze <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adys%C5%82aw_II_Jagiello%C5%84czyk\" target=\"_blank\" rel=\"noopener noreferrer\">Władysława II</a>, króla Czech i Węgier. Inni uważają, że był to pseudonim Nicolausa Olahisa; jeszcze inni twierdzą, że chodzi tu o Menyhérta Miklósa. <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">Łaciński</a> przydomek \"Cibinensis\" wskazuje, że chodzi tu o człowieka pochodzącego z węgierskiego miasta Nagyszeben (obecnie <a href=\"https://pl.wikipedia.org/wiki/Sybin\" target=\"_blank\" rel=\"noopener noreferrer\">Sybin</a> w <a href=\"https://pl.wikipedia.org/wiki/Rumunia\" target=\"_blank\" rel=\"noopener noreferrer\">Rumunii</a>, (<a href=\"https://pl.wikipedia.org/wiki/Siedmiogr%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">Siedmiogród</a>)).", "Maddox": "<b>Maddox</b> – głównie męskie imię używane w krajach anglojęzycznych wywodzące się od walijskiego nazwiska znaczącego „syn Madoca”. <a href=\"https://pl.wikipedia.org/wiki/Madoc_ab_Owain_Gwynedd\" target=\"_blank\" rel=\"noopener noreferrer\">Madoc</a> lub Madog był legendarnym walijskim księciem, który według walijskiego folkloru popłynął do <a href=\"https://pl.wikipedia.org/wiki/Nowy_%C5%9Awiat\" target=\"_blank\" rel=\"noopener noreferrer\">Nowego Świata</a> trzysta lat przed <a href=\"https://pl.wikipedia.org/wiki/Krzysztof_Kolumb\" target=\"_blank\" rel=\"noopener noreferrer\">Krzysztofem Kolumbem</a>. Imię oznacza „pomyślny/fortunny” i pochodzi od walijskiego słowa „mad”.", "Matheo": "Współpraca przyniosła EP-kę, która ukazała się w 2004 w Magazynie Hip-Hop. Matheo, poza rapowaniem, zaczął tworzyć muzykę. Jego pracę pierwszy raz można było usłyszeć na <a href=\"https://pl.wikipedia.org/wiki/Nielegal\" target=\"_blank\" rel=\"noopener noreferrer\">nielegalu</a> z Maciejem „Hajdim” Hajdukiem (jednym z członków tworzących formację ZT Zasięg) pt. <i>Czas Nastał</i>. Przełomem w jego karierze był rok 2004. Wtedy został wyłoniony z konkursu dla producentów, organizowanym przez wytwórnię <a href=\"https://pl.wikipedia.org/wiki/Wielkie_Jo%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkie Joł</a>, dzięki czemu wyprodukował jeden utwór na płytę <a href=\"https://pl.wikipedia.org/wiki/Tede\" target=\"_blank\" rel=\"noopener noreferrer\">Tedego</a> <i><a href=\"https://pl.wikipedia.org/wiki/Notes_(album)\" target=\"_blank\" rel=\"noopener noreferrer\">Notes</a></i>. Wtedy już producent nawiązał bliską współpracę z wytwórnią.", "Mściwoj": "<b>Mściwoj</b>, <b>Mszczujwoj</b> – <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów „mścić (się)” i „woj”, oznaczające prawdopodobnie tego, który \"mści swoich współtowarzyszy\". Jego pomorskim odpowiednikiem może być <a href=\"https://pl.wikipedia.org/wiki/Miestwin\" target=\"_blank\" rel=\"noopener noreferrer\">Miestwin</a>. Na temat <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a> patrz również wyjaśnienia pod hasłem <a href=\"https://pl.wikipedia.org/wiki/M%C5%9Bciwoj_I_gda%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Mściwoj I</a>.", "M": "<b>M</b> (<i>em</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>m</b>) – trzynasta <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a> i siedemnasta <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. Oznacza zwykle w danym języku <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę wargową nosową</a>, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">m</a>].", "Mor": "Próchnica, a ściślej jej <a href=\"https://pl.wikipedia.org/wiki/Poziom_organiczny\" target=\"_blank\" rel=\"noopener noreferrer\">poziom organiczny</a> jest oznaczany w <a href=\"https://pl.wikipedia.org/wiki/Gleboznawstwo\" target=\"_blank\" rel=\"noopener noreferrer\">gleboznawstwie</a> literą O.", "Mir": "<b>Mir</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego.</a> Powstało jako zdrobnienie imion np: <a href=\"https://pl.wikipedia.org/wiki/Miros%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Mirosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Jaromir\" target=\"_blank\" rel=\"noopener noreferrer\">Jaromir</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomir\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomir</a>, <a href=\"https://pl.wikipedia.org/wiki/Radomir\" target=\"_blank\" rel=\"noopener noreferrer\">Radomir</a>, Stanimir itd.", "Merlin": "Trzeci cykl walijskiej triady podaje, że Clas Myrrdin (Samotnia Merlina)&#160;była nazwą Wielkiej Brytanii. Według niektórych (A.O.H. Jarmana), słowo Myrddin jest walijską wersją rzymskiej nazwy Carmarthen. Kontrastuje to z popularnym, lecz fałszywym ludowym przekazem, że miasto zostało nazwane na cześć wieszcza. Nazwa Carmarthen wywodzi się od rzymskiej nazwy miasta Moridunum, które pochodzi od nazwy \"moridunon\" oznaczającej morską twierdzę.", "Malwin": "<b>Malwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, stanowiące męski odpowiednik żeńskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Malwina\" target=\"_blank\" rel=\"noopener noreferrer\">Malwina</a>, pochodzenia literackiego.", "Malkolm": "<b>Malkolm</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gaelicki_szkocki\" target=\"_blank\" rel=\"noopener noreferrer\">szkockiego</a>. Spolszczona forma imienia <i>Malcolm</i>. Wywodzi się od słów <i>Mael Coluim</i> oznaczających naśladujący świętego Kolomba lub podążający za nim. Nosiło je wielu królów <a href=\"https://pl.wikipedia.org/wiki/Szkocja\" target=\"_blank\" rel=\"noopener noreferrer\">Szkocji</a>, m.in. <a href=\"https://pl.wikipedia.org/wiki/Malcolm_III\" target=\"_blank\" rel=\"noopener noreferrer\">Malkolm III</a> uwieczniony w dramacie <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Williama Shakespeare</a> <a href=\"https://pl.wikipedia.org/wiki/Makbet\" target=\"_blank\" rel=\"noopener noreferrer\">Makbet</a>.", "Morfeusz": "<b>Morfeusz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Μορφεύς, <i>Morpheus</i>, od <i>morphe</i> – <i>kształt</i>, <i>postać</i>, <i>forma</i>; <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Morpheus</em>) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> bóg i uosobienie marzeń sennych. Jego ojcem był <a href=\"https://pl.wikipedia.org/wiki/Hypnos_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Hypnos</a> Bóg snów, a stryjem <a href=\"https://pl.wikipedia.org/wiki/Tanatos_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Tanatos</a>, braćmi zaś <a href=\"https://pl.wikipedia.org/wiki/Fobetor\" target=\"_blank\" rel=\"noopener noreferrer\">Ikelos</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Fantasos\" target=\"_blank\" rel=\"noopener noreferrer\">Fantasos</a>. Postać Morfeusza pojawia się w \"Metamorfozach\" Owidiusza, gdzie odgrywa kluczową rolę w historii <a href=\"https://pl.wikipedia.org/wiki/Alkione_(c%C3%B3rka_Eola)\" target=\"_blank\" rel=\"noopener noreferrer\">Alkione (córka Eola)</a> i Ceiksa. Miał zdolność przybierania wyglądu dowolnej ludzkiej formy i naśladowania typowych dla niej gestów i słów. Wyobrażano go sobie jako uskrzydloną postać o wielkich i szybkich skrzydłach, dzięki którym mógł się bezszelestnie przemieszczać na duże odległości.", "Marcjusz": "<b>Marcjusz</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a>, powstałe od nazwy rodu <i>Marcii/Martii</i> (pol. Marcjusze), które pierwotnie stanowiło <a href=\"https://pl.wikipedia.org/wiki/Nazwisko_patronimiczne\" target=\"_blank\" rel=\"noopener noreferrer\">patronimik</a> od <a href=\"https://pl.wikipedia.org/wiki/Marek\" target=\"_blank\" rel=\"noopener noreferrer\">Marka</a>, oznaczając „syn Marka, przynależny do Marka”. Istnieje patron tego imienia, <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Marcjusz\" target=\"_blank\" rel=\"noopener noreferrer\">św. Marcjusz</a>.", "Masahiro": "<b>Masahiro</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まさひろ, マサヒロ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Makoto": "<b>Makoto</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まこと, マコト) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety, jak i przez mężczyzn.", "Mars": "<b>Mars</b> – czwarta od <a href=\"https://pl.wikipedia.org/wiki/S%C5%82o%C5%84ce\" target=\"_blank\" rel=\"noopener noreferrer\">Słońca</a> <a href=\"https://pl.wikipedia.org/wiki/Planeta\" target=\"_blank\" rel=\"noopener noreferrer\">planeta</a> <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_S%C5%82oneczny\" target=\"_blank\" rel=\"noopener noreferrer\">Układu Słonecznego</a>. Krąży między orbitą <a href=\"https://pl.wikipedia.org/wiki/Ziemia\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemi</a> a <a href=\"https://pl.wikipedia.org/wiki/Pas_planetoid\" target=\"_blank\" rel=\"noopener noreferrer\">pasem planetoid</a> dzielącym go od orbity <a href=\"https://pl.wikipedia.org/wiki/Jowisz\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Planeta została nazwana od imienia rzymskiego boga wojny – <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>, ze względu na <a href=\"https://pl.wikipedia.org/wiki/Barwa\" target=\"_blank\" rel=\"noopener noreferrer\">barwę</a>, która przy obserwacji z <a href=\"https://pl.wikipedia.org/wiki/Ziemia\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemi</a> wydaje się rdzawo-czerwona i kojarzyła się starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzymianie\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymianom</a> z pożogą wojenną. Odcień ten bierze się od <a href=\"https://pl.wikipedia.org/wiki/Tlenki_%C5%BCelaza\" target=\"_blank\" rel=\"noopener noreferrer\">tlenków żelaza</a> pokrywających powierzchnię. Mars jest <a href=\"https://pl.wikipedia.org/wiki/Planeta_wewn%C4%99trzna\" target=\"_blank\" rel=\"noopener noreferrer\">planetą wewnętrzną</a> z cienką <a href=\"https://pl.wikipedia.org/wiki/Atmosfera\" target=\"_blank\" rel=\"noopener noreferrer\">atmosferą</a>, o powierzchni usianej <a href=\"https://pl.wikipedia.org/wiki/Krater_uderzeniowy\" target=\"_blank\" rel=\"noopener noreferrer\">kraterami uderzeniowymi</a>, podobnie jak powierzchnia <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99%C5%BCyc\" target=\"_blank\" rel=\"noopener noreferrer\">Księżyca</a> i wielu innych ciał <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_S%C5%82oneczny\" target=\"_blank\" rel=\"noopener noreferrer\">Układu Słonecznego</a>. Powierzchnia wykazuje formy podobne do ziemskich: <a href=\"https://pl.wikipedia.org/wiki/Wulkan\" target=\"_blank\" rel=\"noopener noreferrer\">wulkany</a>, <a href=\"https://pl.wikipedia.org/wiki/Dolina\" target=\"_blank\" rel=\"noopener noreferrer\">doliny</a>, <a href=\"https://pl.wikipedia.org/wiki/Kanion\" target=\"_blank\" rel=\"noopener noreferrer\">kaniony</a>, <a href=\"https://pl.wikipedia.org/wiki/Pustynia\" target=\"_blank\" rel=\"noopener noreferrer\">pustynie</a> i polarne czapy lodowe. Okres obrotu wokół własnej osi jest niewiele dłuższy niż ziemski i wynosi 24,6229 godziny (24 h 37 m 22 s). Na Marsie znajduje się najwyższe <a href=\"https://pl.wikipedia.org/wiki/Wzniesienie\" target=\"_blank\" rel=\"noopener noreferrer\">wzniesienie</a> w Układzie Słonecznym – <a href=\"https://pl.wikipedia.org/wiki/Olympus_Mons\" target=\"_blank\" rel=\"noopener noreferrer\">Olympus Mons</a> i największy kanion – <a href=\"https://pl.wikipedia.org/wiki/Valles_Marineris\" target=\"_blank\" rel=\"noopener noreferrer\">Valles Marineris</a>. Gładki obszar równinny <a href=\"https://pl.wikipedia.org/wiki/Vastitas_Borealis\" target=\"_blank\" rel=\"noopener noreferrer\">Vastitas Borealis</a> na półkuli północnej, który obejmuje 40% powierzchni planety, może być pozostałością ogromnego uderzenia. W przeciwieństwie do <a href=\"https://pl.wikipedia.org/wiki/Ziemia\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemi</a>, Mars jest mało aktywny <a href=\"https://pl.wikipedia.org/wiki/Geologia\" target=\"_blank\" rel=\"noopener noreferrer\">geologicznie</a> i nie zachodzą na nim zjawiska <a href=\"https://pl.wikipedia.org/wiki/Tektonika_p%C5%82yt\" target=\"_blank\" rel=\"noopener noreferrer\">tektoniczne</a>.", "Mścigniew": "<b>Mścigniew</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Oznacza: ten, który mści, zwalcza swój gniew. Wspomniane w dokumentach z 1234 roku. Mścigniew <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/19_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">19 grudnia</a>.", "Miłowit": "<b>Miłowit</b>, <b>Miłwit</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Mił(o)-</i> (\"miły\") i <i>-wit</i> (\"pan, władca\"). Imię to mogło oznaczać np. \"miłujący władcę\" albo \"umiłowany przez władcę\".", "Mściwój": "<b>Mściwoj</b>, <b>Mszczujwoj</b> – <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów „mścić (się)” i „woj”, oznaczające prawdopodobnie tego, który \"mści swoich współtowarzyszy\". Jego pomorskim odpowiednikiem może być <a href=\"https://pl.wikipedia.org/wiki/Miestwin\" target=\"_blank\" rel=\"noopener noreferrer\">Miestwin</a>. Na temat <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a> patrz również wyjaśnienia pod hasłem <a href=\"https://pl.wikipedia.org/wiki/M%C5%9Bciwoj_I_gda%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Mściwoj I</a>.", "Miki": "<b>Miki</b>, <b>łyszczyki</b> – grupa <a href=\"https://pl.wikipedia.org/wiki/Minera%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">minerałów</a> zaliczana do gromady <a href=\"https://pl.wikipedia.org/wiki/Krzemiany\" target=\"_blank\" rel=\"noopener noreferrer\">krzemianów</a>. Nazwa „mika” pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>mica</i> (ziarno) lub <i>micare</i> (błyszczeć).", "Manswet": "<b>Manswet</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> przymiotnika <i>mansuetus</i> (łagodny, miły).", "Mai": "<b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Masato": "<b>Masato</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まさと, マサト) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Mścibor": "<b>Mścibor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Mści-</i> („mścić”) i <i>-bor</i> („walczyć, zmagać się”). Mogło oznaczać „tego, który mści się bojem”.", "Maryn": "<b>Maryn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od przymiotnika <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>marinus</em> („morski”). Wersją oboczną jest <a href=\"https://pl.wikipedia.org/wiki/Maryniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maryniusz</a>. Wśród patronów tego imienia św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Maryn_z_San_Marino\" target=\"_blank\" rel=\"noopener noreferrer\">Maryn</a>, od imienia którego pochodzi nazwa państwa <a href=\"https://pl.wikipedia.org/wiki/San_Marino\" target=\"_blank\" rel=\"noopener noreferrer\">San Marino</a>.", "Maksymin": "<b>Maksymin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wśród patronów – św. Maksymin (†<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>).", "Miranda": "<b>Miranda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>miranda</i> oznaczającego \"godna podziwu\". Imię zostało pierwszy raz użyte przez <a href=\"https://pl.wikipedia.org/wiki/William_Szekspir\" target=\"_blank\" rel=\"noopener noreferrer\">Williama Shakespeare'a</a> w dramacie <i><a href=\"https://pl.wikipedia.org/wiki/Burza_(sztuka)\" target=\"_blank\" rel=\"noopener noreferrer\">Burza</a></i>.", "Mojmir": "<b>Mojmir</b> – starosłowiańskie (w tym staropolskie) <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Moj-</i> (\"mój\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Prawdopodobnie oznaczało \"moje dobro\", \"mój skarb\".", "Mierosław": "<b>Mirosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Imię <i>Mirosław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poganie\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członów <i>Miro-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ps.</a> <i>*mirъ</i> „pokój”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">stpol.</a> <i>mir</i>, <i>mier</i> - „pokój, bezpieczeństwo, przyjaźń”) oraz <i>-sław</i> („sława”). Mogło oznaczać „ten, który sławi pokój” albo „ten, który zdobywa sławę poprzez zaprowadzenie porządku, pokoju”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Masashi": "<b>Masashi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まさし, マサシ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Maurycjusz": "<b>Maurycjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>", "Malachiasz": "<b>Malachiasz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, oznaczające „mój posłaniec” albo „mój anioł”. Patronem tego imienia jest prorok z <a href=\"https://pl.wikipedia.org/wiki/V_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">V wieku p.n.e.</a>, autor biblijnej <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Malachiasza\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Malachiasza</a>, oraz pierwszy irlandzki święty bp <a href=\"https://pl.wikipedia.org/wiki/Malachiasz_(biskup)\" target=\"_blank\" rel=\"noopener noreferrer\">Malachiasz</a>.", "Mordechaj": "<b>Mordechaj</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> מרדכי) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%BBydzi\" target=\"_blank\" rel=\"noopener noreferrer\">żydowskiego</a>.", "Mariush": "W latach 2001–2014 był członkiem <a href=\"https://pl.wikipedia.org/wiki/Kabaret_Limo\" target=\"_blank\" rel=\"noopener noreferrer\">Kabaretu Limo</a>. Po zakończeniu działalności tej formacji zajmuje się głównie pisaniem sztuk oraz improwizacją komediową.", "Miłogost": "<b>Miłogost</b>, <b>Miłgost</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Miło-</i> („miły”, „miłujący”) i <i>-gost</i> („goście”, „gościć”). Mogło oznaczać „przyjaznego gościom”.", "Maryna": "Imię Maryna jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Maryn\" target=\"_blank\" rel=\"noopener noreferrer\">Maryn</a>, w Polsce niezwykle rzadkim (w 1994 roku nosiła je jedna osoba, w roku 2001 – 203 osoby, zaś w wariancie <i>Marina</i> – 362). Imię to wywodzi się od imienia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Marinus</em>, a to z kolei powstało z przymiotnika <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>marinus</em> („morski”). Imię Maryna – rozumiane jako żeński odpowiednik imienia Maryn – poświadczone jest w Polsce już w XV wieku (najwcześniej w 1443 roku). Zdrobnienie od niego brzmi Marynia. Marina to cudzoziemski wariant imienia Maryna; trudno powiedzieć, skąd przybyło do Polski, z uwagi na podobną formę w prawie wszystkich językach europejskich.", "Mikal": "<b>Mikal</b> (hebr. מיכל; skrócona forma imienia <i>Michael</i> − <i>kto jest jak Bóg</i>) − córka <a href=\"https://pl.wikipedia.org/wiki/Saul_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Saula</a>, króla Izraela, pierwsza żona króla <a href=\"https://pl.wikipedia.org/wiki/Dawid_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Dawida</a>. Zapis historii Mikal przekazują <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijne</a> Księgi Samuela.", "Miromir": "<b>Mirogod</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Miro-</i> (\"pokój, spokój, dobro\") oraz <i>-god</i> (\"robić coś w stosownym czasie, dopasowywać, czynić odpowiednim\"). Mogło oznaczać \"ten, który czyni pokój\". Por. <a href=\"https://pl.wikipedia.org/wiki/Godzimir\" target=\"_blank\" rel=\"noopener noreferrer\">Godzimir</a>, imię złożone z tych samych członów w odwrotnej kolejności.", "Maja": "<b>Maja</b> – imię żeńskie pochodzenia greckiego, wywodzące się od słowa <i>μαῖα (maia)</i> oznaczającego „dobrą matkę”, „damę” lub „przybraną matkę”. W mitologiach greckiej i rzymskiej <a href=\"https://pl.wikipedia.org/wiki/Maja_(mitologia_grecka)\" target=\"_blank\" rel=\"noopener noreferrer\">Maja</a> była najstarszą z <a href=\"https://pl.wikipedia.org/wiki/Nimfy\" target=\"_blank\" rel=\"noopener noreferrer\">nimf</a> – <a href=\"https://pl.wikipedia.org/wiki/Plejady_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Plejad</a>, córek <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a> i <a href=\"https://pl.wikipedia.org/wiki/Plejone_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Plejone</a>, oraz matką <a href=\"https://pl.wikipedia.org/wiki/Hermes\" target=\"_blank\" rel=\"noopener noreferrer\">Hermesa</a>.", "Mauryliusz": "<b>Mauryliusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, którego patronem jest m.in. św. Mauryliusz, biskup <a href=\"https://pl.wikipedia.org/wiki/Angers\" target=\"_blank\" rel=\"noopener noreferrer\">Angers</a> we <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a>. <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/13_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">13 września</a>.", "Maruti": "Indyjskie przedsiębiorstwo od 1983 roku produkuje samochody na licencji Suzuki. Pierwszym pojazdem produkowanym w Indiach na tej zasadzie było <a href=\"https://pl.wikipedia.org/wiki/Maruti_800\" target=\"_blank\" rel=\"noopener noreferrer\">Maruti 800</a>, odpowiednik modelu <a href=\"https://pl.wikipedia.org/wiki/Suzuki_Alto\" target=\"_blank\" rel=\"noopener noreferrer\">Suzuki Alto</a>. Był to najlepiej sprzedający się samochód w Indiach.", "Magid": "<b>Magid</b> lub <b>maggid</b> (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מַגִּיד&#8206; „przemawiający”) – w <a href=\"https://pl.wikipedia.org/wiki/Judaizm\" target=\"_blank\" rel=\"noopener noreferrer\">judaizmie</a> wschodnioeuropejskim tytuł przyznawany wędrownym kaznodziejom, którzy często zarabiali na życie opłatami zbieranymi w różnych gminach. Z racji tego, że dawni rabini byli bardziej uczonymi i znawcami pisma niż kaznodziejami, długie, barwne i przystępne kazania (często w <a href=\"https://pl.wikipedia.org/wiki/Jidysz\" target=\"_blank\" rel=\"noopener noreferrer\">jidysz</a>) znajdowały wielu chętnych słuchaczy. Termin ten oznacza także pozaziemskiego mentora, który nawiązuje kontakt z ludźmi za pomocą nawiedzeń, snów, wizji, a także słów wypowiedzianych ich własnymi ustami. Wielu mistyków posiadało własnego magida, który wprowadzał ich w tajniki kabały. Posiadanie magida było znakiem duchowej wyższości takiej osoby. O <a href=\"https://pl.wikipedia.org/wiki/Eliasz_ben_Salomon_Zalman\" target=\"_blank\" rel=\"noopener noreferrer\">Eliaszu Gaonie z Wilna</a> mówiono, że odmówił przyjęcia magida, gdyż nie chciał poznać Tory bez wysiłku ze swej strony. Najsłynniejszym magidem był magid <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Karo\" target=\"_blank\" rel=\"noopener noreferrer\">Józef Karo</a>, a niektóre prawdy, które objawił, Karo zapisał w dzienniku <i>Magid Meiszarim</i>.", "Minoru": "<b>Minoru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みのる, ミノル) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Máni": "<b>Mani</b> – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_nordycka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii nordyckiej</a> bóg Księżyca, syn Glaur i <a href=\"https://pl.wikipedia.org/wiki/Olbrzym_(istota)\" target=\"_blank\" rel=\"noopener noreferrer\">olbrzyma</a> Mundilfariego. Każdej nocy podgryzany przez <a href=\"https://pl.wikipedia.org/wiki/Hati\" target=\"_blank\" rel=\"noopener noreferrer\">Hatiego</a>, wiedzie przez niebo księżyc. Gdy nadejdzie <a href=\"https://pl.wikipedia.org/wiki/Ragnar%C3%B6k\" target=\"_blank\" rel=\"noopener noreferrer\">Ragnarök</a>, Hati schwyta Mániego. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku staronordyjskim</a> słowo <i>máni</i> było pospolitym słowem oznaczającym księżyc.", "Monika": "<b>Monika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o znaczeniu i pochodzeniu trudnym do objaśnienia. Według niektórych badaczy imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa „monos” oznaczającego <i>jeden</i>, <i>sam</i>, <i>pojedynczy</i>, <i>jedynak</i> i <i>jedynaczka</i>. Z tego samego rdzenia pochodzą takie słowa jak: <a href=\"https://pl.wikipedia.org/wiki/Monogamia\" target=\"_blank\" rel=\"noopener noreferrer\">monogamia</a>, <a href=\"https://pl.wikipedia.org/wiki/Monoteizm\" target=\"_blank\" rel=\"noopener noreferrer\">monoteizm</a>, monaster (klasztor). Inne źródło podaje, że imię to wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> „monaché”, co znaczy <i>samotna</i>, <i>odosobniona</i>; we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> zakonnica zwana jest <i>monaca</i>, a w niektórych dialektach wręcz <i>monica</i>.", "Mirwais": "<b>Mirwais Ahmadzaï</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/23_pa%C5%BAdziernika\" target=\"_blank\" rel=\"noopener noreferrer\">23 października</a> <a href=\"https://pl.wikipedia.org/wiki/1960\" target=\"_blank\" rel=\"noopener noreferrer\">1960</a> w <a href=\"https://pl.wikipedia.org/wiki/Lozanna\" target=\"_blank\" rel=\"noopener noreferrer\">Lozannie</a> w <a href=\"https://pl.wikipedia.org/wiki/Szwajcaria\" target=\"_blank\" rel=\"noopener noreferrer\">Szwajcarii</a>) – <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">francuski</a> <a href=\"https://pl.wikipedia.org/wiki/Muzyk\" target=\"_blank\" rel=\"noopener noreferrer\">muzyk</a>, <a href=\"https://pl.wikipedia.org/wiki/Kompozytor\" target=\"_blank\" rel=\"noopener noreferrer\">kompozytor</a>, producent <a href=\"https://pl.wikipedia.org/wiki/Muzyka\" target=\"_blank\" rel=\"noopener noreferrer\">muzyczny</a> i <a href=\"https://pl.wikipedia.org/wiki/DJ\" target=\"_blank\" rel=\"noopener noreferrer\">DJ</a>, podpisujący się też często jedynie jako <b>Mirwais</b>. Swoje nazwisko odziedziczył po <a href=\"https://pl.wikipedia.org/wiki/Afganistan\" target=\"_blank\" rel=\"noopener noreferrer\">afgańskim</a> ojcu, matka była z pochodzenia <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszką</a>.", "Maro": "<b>Maro</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> oznaczające urzędnika municypalnego. Przekształciło się ono z czasem w cognomen, które nosił na przykład <a href=\"https://pl.wikipedia.org/wiki/Wergiliusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz Wergilusz Maro</a>.", "Meliton": "<b>Meliton</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, utworzone od wyrazu pospolitego méli, -itos 'miód' za pomocą <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> -n, oznaczające 'człowieka jak miód'. Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Meliton_z_Sardes\" target=\"_blank\" rel=\"noopener noreferrer\">Meliton z Sardes</a>, święty z II wieku.", "Montana": "Nazwa prawdopodobnie pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszpańskiego</a> słowa <em>montaña</em>, które znaczy „góra”. Chociaż Montana kojarzona jest przede wszystkim z położonymi na jej obszarze górami, około 60% terytorium stanu pokrywa <a href=\"https://pl.wikipedia.org/wiki/Preria\" target=\"_blank\" rel=\"noopener noreferrer\">preria</a>, wchodząca w skład <a href=\"https://pl.wikipedia.org/wiki/Wielkie_R%C3%B3wniny\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkich Równin</a>. Region nazywany jest „Stanem Skarbów” (<em>Treasure State</em>) ze względu na jego ogromne bogactwo mineralne, a także „Krainą lśniących gór” (<em>Land of the Shining Mountains</em>) i „Krainą wielkiego nieba” (<em>Big Sky Country</em>). Zróżnicowana gospodarka Montany historycznie bazuje na rolnictwie, górnictwie i przemyśle drzewnym. W XXI wieku na znaczeniu zyskały usługi, finanse, nieruchomości, czy turystyka. W Montanie znajduje się <a href=\"https://pl.wikipedia.org/wiki/Park_Narodowy_Glacier_(USA)\" target=\"_blank\" rel=\"noopener noreferrer\">Park Narodowy Glacier</a> oraz północny, niewielki fragment <a href=\"https://pl.wikipedia.org/wiki/Park_Narodowy_Yellowstone\" target=\"_blank\" rel=\"noopener noreferrer\">Parku Narodowego Yellowstone</a>. Przez stan przechodzi <a href=\"https://pl.wikipedia.org/wiki/Wododzia%C5%82_kontynentalny_Ameryki\" target=\"_blank\" rel=\"noopener noreferrer\">wododział kontynentalny Ameryki</a>.", "Mścibór": "<b>Mścibor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Mści-</i> („mścić”) i <i>-bor</i> („walczyć, zmagać się”). Mogło oznaczać „tego, który mści się bojem”.", "Mitrofan": "<b>Metrofan</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>Μητροφανης</i>, złożone z członów <i>μητηρ (meter)</i> — \"matki\" i <i>φανης (phanes)</i> — \"pojawienie się, objawienie się\", co oznacza \"objawienie matki\". Patronem tego imienia jest św. Metrofan, biskup <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_Bizanty%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Bizancjum</a> (III–IV wiek). U Słowian wschodnich imię to rozpowszechniło się w formie <i><b>Mitrofan</b></i>.", "Mara": "<b>Mara</b> – włoskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (hebr. מָרָא), występujące w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>.", "Miłorad": "<b>Miłorad</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Miło-</i> (\"miły\") i <i>-rad</i> (\"być zadowolonym, chętnym, cieszyć się\").", "Manabu": "<b>Manabu</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まなぶ, マナブ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Madhava": "<b>Madhava</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/1340\" target=\"_blank\" rel=\"noopener noreferrer\">1340</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/1425\" target=\"_blank\" rel=\"noopener noreferrer\">1425</a>) – <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjski</a> <a href=\"https://pl.wikipedia.org/wiki/Matematyk\" target=\"_blank\" rel=\"noopener noreferrer\">matematyk</a> i <a href=\"https://pl.wikipedia.org/wiki/Astronom\" target=\"_blank\" rel=\"noopener noreferrer\">astronom</a> pochodzący z miejscowości Sangamagramma położonej w północno-zachodnich Indiach (dzisiejsza <a href=\"https://pl.wikipedia.org/wiki/Kerala\" target=\"_blank\" rel=\"noopener noreferrer\">Kerala</a>); wniósł pionierski wkład w badania nad <a href=\"https://pl.wikipedia.org/wiki/Szereg_(matematyka)\" target=\"_blank\" rel=\"noopener noreferrer\">szeregami nieskończonymi</a>, <a href=\"https://pl.wikipedia.org/wiki/Analiza_matematyczna\" target=\"_blank\" rel=\"noopener noreferrer\">analizą matematyczną</a>, <a href=\"https://pl.wikipedia.org/wiki/Trygonometria\" target=\"_blank\" rel=\"noopener noreferrer\">trygonometrią</a>, <a href=\"https://pl.wikipedia.org/wiki/Geometria\" target=\"_blank\" rel=\"noopener noreferrer\">geometrią</a> i <a href=\"https://pl.wikipedia.org/wiki/Algebra\" target=\"_blank\" rel=\"noopener noreferrer\">algebrą</a>.", "Mia": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Michio": "<b>Michio</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;道雄 lub 通夫) – męskie imię japońskie.", "Mukti": "<b>Mukti</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> मुक्ति) – termin <a href=\"https://pl.wikipedia.org/wiki/Filozofia_indyjska\" target=\"_blank\" rel=\"noopener noreferrer\">filozofii indyjskiej</a> oznaczający <a href=\"https://pl.wikipedia.org/wiki/Wyzwolenie_w_hinduizmie\" target=\"_blank\" rel=\"noopener noreferrer\">wyzwolenie</a> w doktrynach <a href=\"https://pl.wikipedia.org/wiki/Upaniszady\" target=\"_blank\" rel=\"noopener noreferrer\">Upaniszad</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Wedanta\" target=\"_blank\" rel=\"noopener noreferrer\">wedanty</a>.", "Melor": "<b>Melsor</b> (ros. Мэлсор) – imię, będące akronimem powstałe od pierwszych liter: <a href=\"https://pl.wikipedia.org/wiki/Karl_Marx\" target=\"_blank\" rel=\"noopener noreferrer\"><b>M</b>arks</a>-<a href=\"https://pl.wikipedia.org/wiki/Friedrich_Engels\" target=\"_blank\" rel=\"noopener noreferrer\"><b>E</b>ngels</a>-<a href=\"https://pl.wikipedia.org/wiki/W%C5%82odzimierz_Lenin\" target=\"_blank\" rel=\"noopener noreferrer\"><b>L</b>enin</a>-<a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Stalin\" target=\"_blank\" rel=\"noopener noreferrer\"><b>S</b>talin</a>-<a href=\"https://pl.wikipedia.org/wiki/Rewolucja_pa%C5%BAdziernikowa\" target=\"_blank\" rel=\"noopener noreferrer\"><b>O</b>ktiabr'skaja <b>R</b>iewolucyja</a>. Po śmierci Stalina, tezach wygłoszonych na <a href=\"https://pl.wikipedia.org/wiki/XX_Zjazd_KPZR\" target=\"_blank\" rel=\"noopener noreferrer\">XX Zjeździe KPZR</a> z imienia Melsor usunięto literę „s”, zmieniając je na Melor: <b>M</b>arks-<b>E</b>ngels-<b>L</b>enin-<b>O</b>ktiabr'skaja <b>R</b>iewolucyja.", "Mitsuru": "<b>Mitsuru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みつる, ミツル) – głównie męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, bardzo rzadko noszone przez kobiety.", "Myślibor": "<b>Myślibor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Myśli-</i> (\"myśleć\") i <i>-bor</i> (\"walczyć, zmagać się\"). Być może oznaczało \"tego, który myśli o walce\" albo \"tego, który obmyśla walkę\".", "Makis": "<b>Makia</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a> <i>maquis</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> <i>macchia</i>) – zaroślowa <a href=\"https://pl.wikipedia.org/wiki/Formacja_ro%C5%9Blinna\" target=\"_blank\" rel=\"noopener noreferrer\">formacja roślinna</a> charakterystyczna dla <a href=\"https://pl.wikipedia.org/wiki/Strefa_%C5%9Br%C3%B3dziemnomorska\" target=\"_blank\" rel=\"noopener noreferrer\">obszaru śródziemnomorskiego</a>, kształtująca się zwykle wtórnie w miejscach po usuniętych <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Blinno%C5%9B%C4%87_twardolistna\" target=\"_blank\" rel=\"noopener noreferrer\">lasach twardolistnych</a>, głównie dębowych, rzadziej sosnowych i cyprysowych. Makia w zależności od warunków siedliskowych bywa luźna lub gęsta, niska – wyłącznie zaroślowa (do 2,5 m wysokości), lub wysoka – z udziałem okazałych krzewów i niskich drzew osiągających do 5 m wysokości. Dominują zawsze <a href=\"https://pl.wikipedia.org/wiki/Krzew\" target=\"_blank\" rel=\"noopener noreferrer\">krzewy</a>, zwykle zimozielone o liściach skórzastych, miejscami z większym lub mniejszym udziałem gatunków zrzucających liście zimą. Pod względem fizjonomii i zajmowanych <a href=\"https://pl.wikipedia.org/wiki/Siedlisko_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">siedlisk</a> makia w całym obszarze jej występowania jest podobna, występują jednak znaczne różnice w kompozycji gatunkowej. W płatach bardzo zróżnicowanych warstwę krzewów może tworzyć nawet ok. 30 gatunków. Charakterystyczny dla makii jest silny aromat ze względu na to, że wiele występujących w niej roślin wydziela duże ilości <a href=\"https://pl.wikipedia.org/wiki/Olejek_eteryczny\" target=\"_blank\" rel=\"noopener noreferrer\">olejków eterycznych</a>. Ze względu na gęstość zarośli, duży udział gatunków ciernistych, kolczastych i pnączy makia często bywa bardzo trudna do przebycia.", "Masław": "Według hipotezy <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw_Rospond_(j%C4%99zykoznawca)\" target=\"_blank\" rel=\"noopener noreferrer\">Stanisława Rosponda</a>, <b>Masław</b> jest skróconą formą niezachowanego w pierwotnym brzmieniu imienia <i>Jimasław</i>, który wtórnie utrzymał się jako <a href=\"https://pl.wikipedia.org/wiki/Imis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Jimisław</a>, natomiast w oryginale kroniki Nestora występowała forma Masław, <a href=\"https://pl.wikipedia.org/wiki/Adideacja\" target=\"_blank\" rel=\"noopener noreferrer\">zadideowana</a> następnie z bardziej znaną kopistom formą Mojsław. Inną hipotezą jest założenie <a href=\"https://pl.wikipedia.org/wiki/Maria_Malec_(j%C4%99zykoznawczyni)\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Malec</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Bubak\" target=\"_blank\" rel=\"noopener noreferrer\">Józef Bubaka</a>, że imię to mogło być skrótem od niepoświadczonego imienia <i>*Małosław</i>.", "Markiz": "Wyraz pochodzi z francuskiego <i>marquis</i>, które wywodzi się najwyraźniej z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> słowa oznaczającego granicę (<i>mark</i>). W języku niemieckim odpowiadający tytuł to <i>Markgraf</i>, co można analizować jako <i>Mark + graf</i> = granica + <a href=\"https://pl.wikipedia.org/wiki/Hrabia\" target=\"_blank\" rel=\"noopener noreferrer\">hrabia</a>, tj. hrabia opiekujący się granicami. Dawniej hrabia, który chronił granice, był bardziej uprzywilejowany od innych hrabiów, co tłumaczy stosunkowo wysoką pozycję w hierarchii, tym bardziej, że mógł zdobyte na sąsiadach (przeważnie barbarzyńcach) ziemie dodawać do swojej domeny.", "Milana": "<b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Mimir": "<b>Mimir</b> – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_nordycka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii nordyckiej</a> tajemniczy mędrzec o nieznanym pochodzeniu.", "Mahal": "Najwięecej ochotników pochodziło ze <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stanów Zjednoczonych</a> i <a href=\"https://pl.wikipedia.org/wiki/Wielka_Brytania\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkiej Brytanii</a>. Byli to najczęściej weterani wojskowi z <a href=\"https://pl.wikipedia.org/wiki/II_wojna_%C5%9Bwiatowa\" target=\"_blank\" rel=\"noopener noreferrer\">II wojny światowej</a>. Posiadali oni duże doświadczenie bojowe, często byli to piloci wojskowi.", "Masaru": "<b>Masaru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まさる, マサル) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Miłowan": "<b>Miłowan</b> – słowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie jednoczłonowe, utworzone z członu <i>Miło-</i> (\"miłować\"). Wzmiankowane w dokumentach z 1136 roku. Może oznaczać: miłowany. Popularne zwłaszcza w <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_po%C5%82udniowi\" target=\"_blank\" rel=\"noopener noreferrer\">krajach południowosłowiańskich</a>", "Major": "<b>Major</b> (mjr) – stopień <a href=\"https://pl.wikipedia.org/wiki/Oficer_(wojsko)\" target=\"_blank\" rel=\"noopener noreferrer\">oficerski</a> używany w armiach wielu krajów. Major jest najniższym stopniem w <a href=\"https://pl.wikipedia.org/wiki/Korpus_(wojsko)\" target=\"_blank\" rel=\"noopener noreferrer\">korpusie</a> oficerów starszych, natomiast w <a href=\"https://pl.wikipedia.org/wiki/Historia_Polski_(1918%E2%80%931939)\" target=\"_blank\" rel=\"noopener noreferrer\">okresie międzywojennym</a> wchodził w skład korpusu oficerów sztabowych. W wojsku polskim jest to stopień niższy od <a href=\"https://pl.wikipedia.org/wiki/Podpu%C5%82kownik\" target=\"_blank\" rel=\"noopener noreferrer\">podpułkownika</a>, wyższy od <a href=\"https://pl.wikipedia.org/wiki/Kapitan_(ranga)\" target=\"_blank\" rel=\"noopener noreferrer\">kapitana</a>. Odpowiednikiem majora w <a href=\"https://pl.wikipedia.org/wiki/Marynarka_wojenna\" target=\"_blank\" rel=\"noopener noreferrer\">marynarce wojennej</a> jest <a href=\"https://pl.wikipedia.org/wiki/Komandor_podporucznik\" target=\"_blank\" rel=\"noopener noreferrer\">komandor podporucznik</a>, a w <a href=\"https://pl.wikipedia.org/wiki/Policja\" target=\"_blank\" rel=\"noopener noreferrer\">policji</a> <a href=\"https://pl.wikipedia.org/wiki/Stopnie_s%C5%82u%C5%BCbowe_w_Policji\" target=\"_blank\" rel=\"noopener noreferrer\">podinspektor Policji</a>. Stopień majora występuje również w <a href=\"https://pl.wikipedia.org/wiki/Stra%C5%BC_Graniczna_(Polska)\" target=\"_blank\" rel=\"noopener noreferrer\">Straży Granicznej</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82u%C5%BCba_Wi%C4%99zienna\" target=\"_blank\" rel=\"noopener noreferrer\">Służbie Więziennej</a>, <a href=\"https://pl.wikipedia.org/wiki/Biuro_Ochrony_Rz%C4%85du\" target=\"_blank\" rel=\"noopener noreferrer\">Biurze Ochrony Rządu</a> oraz Służbie Kontrwywiadu i Wywiadu Wojskowego.", "Machabeusz": "<b>Machabeusz</b> – biblijne imię męskie pochodzenia hebrajskiego. Wywodzi się od słowa <em>&#8207;mqqabhak&#8206;</em>, oznaczającego \"<a href=\"https://pl.wikipedia.org/wiki/M%C5%82otek\" target=\"_blank\" rel=\"noopener noreferrer\">młot</a>\". Pojawia się wielokrotnie w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>, szczególnie w <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99gi_Machabejskie\" target=\"_blank\" rel=\"noopener noreferrer\">Księgach Machabejskich</a>.", "Minigniew": "<b>Minigniew</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Mini-</i> (\"minąć\") oraz <i>-gniew</i>. Mogło oznaczać \"tego, którego gniew szybko mija\".", "Muhammad Asad": "<b>Muhammad Asad</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_urdu\" target=\"_blank\" rel=\"noopener noreferrer\">urdu</a>&#160;&#8207;محمد اسد&#8206; urodzony jako <b>Leopold Weiss</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/2_lipca\" target=\"_blank\" rel=\"noopener noreferrer\">2 lipca</a> <a href=\"https://pl.wikipedia.org/wiki/1900\" target=\"_blank\" rel=\"noopener noreferrer\">1900</a> we <a href=\"https://pl.wikipedia.org/wiki/Lw%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Lwowie</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/20_lutego\" target=\"_blank\" rel=\"noopener noreferrer\">20 lutego</a> <a href=\"https://pl.wikipedia.org/wiki/1992\" target=\"_blank\" rel=\"noopener noreferrer\">1992</a> w <a href=\"https://pl.wikipedia.org/wiki/Mijas\" target=\"_blank\" rel=\"noopener noreferrer\">Mijas</a>) – Austriak żydowskiego pochodzenia, dziennikarz, podróżnik, pisarz, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zykoznawstwo\" target=\"_blank\" rel=\"noopener noreferrer\">językoznawca</a>, myśliciel, reformator, <a href=\"https://pl.wikipedia.org/wiki/Dyplomata\" target=\"_blank\" rel=\"noopener noreferrer\">dyplomata</a> i politolog.", "Masami": "<b>Masami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まさみ,マサミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety, jak i przez mężczyzn.", "Melaniusz": "<b>Melaniusz</b> – imię męskie pochodzenia greckiego.", "Mahmoud Ahmed": "<b>Mahmoud Ahmed</b> (<i><a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_amharski\" target=\"_blank\" rel=\"noopener noreferrer\">amh.</a></i> ማሀሙድ አህመድ; ur. <a href=\"https://pl.wikipedia.org/wiki/8_maja\" target=\"_blank\" rel=\"noopener noreferrer\">8</a> lub <a href=\"https://pl.wikipedia.org/wiki/18_maja\" target=\"_blank\" rel=\"noopener noreferrer\">18 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1941\" target=\"_blank\" rel=\"noopener noreferrer\">1941</a>) – <a href=\"https://pl.wikipedia.org/wiki/Etiopia\" target=\"_blank\" rel=\"noopener noreferrer\">etiopski</a> muzyk pochodzący z ludu <a href=\"https://pl.wikipedia.org/wiki/Gurage\" target=\"_blank\" rel=\"noopener noreferrer\">Gurage</a>.", "Magdalena": "<b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Marta": "<b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Mame": "<b>MAME</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Multiple Arcade Machine Emulator</em>) – <a href=\"https://pl.wikipedia.org/wiki/Emulator\" target=\"_blank\" rel=\"noopener noreferrer\">emulator</a> pozwalający na uruchomienie gier ze starych <a href=\"https://pl.wikipedia.org/wiki/Automat_do_gry\" target=\"_blank\" rel=\"noopener noreferrer\">automatów do gry</a> na współczesnych platformach sprzętowych. Twórcą emulatora jest Nicola Salmoria, a pierwszą wersję programu (0.1) stworzył w 1997 roku. Serwis <a href=\"https://pl.wikipedia.org/wiki/Joystiq\" target=\"_blank\" rel=\"noopener noreferrer\">Joystiq</a> umieścił MAME na liście programów, które każdy gracz powinien posiadać.", "Mira": "<b>Mira</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Jest skróconą (zdrobniałą) formą <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Miros%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Mirosława</a>. Imię pochodzenia słowiańskiego o niejasnej etymologii. Najprawdopodobniej wywodzi się od rdzenia mir (\"pokój, świat\") i oznacza: \"zgodna, spokojna\". Inna hipoteza zakłada, iż funkcjonuje samodzielnie jako skrót imion Mirosława, Miranda, Sławomira itp. Kolejna teoria głosi, że jest to po prostu żeński odpowiednik imienia Miron. Istnieje także hinduskie imię żeńskie o tym samym brzmieniu, wywodzące się ze słowa oznaczającego \"morze, ocean\" w języku <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryt</a>. Nosiła je XVI-wieczna <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjska</a> księżniczka, znana wyznawczyni boga <a href=\"https://pl.wikipedia.org/wiki/Kryszna\" target=\"_blank\" rel=\"noopener noreferrer\">Kriszny</a>. Może stanowić także formę skróconą niesłowiańskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Miranda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miranda</a>.", "Myślibór": "<b>Myślibor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Myśli-</i> (\"myśleć\") i <i>-bor</i> (\"walczyć, zmagać się\"). Być może oznaczało \"tego, który myśli o walce\" albo \"tego, który obmyśla walkę\".", "Martyna": "<b>Martyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Marcin\" target=\"_blank\" rel=\"noopener noreferrer\">Marcin</a> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Martinus</em>, „należący do <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa”</a>). Błędnym skojarzeniem jest, że Martyna powstała od imienia <a href=\"https://pl.wikipedia.org/wiki/Marta_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Marta</a>. Spotykana jest również forma <b>Marcina</b>. W wielu językach imię to występuje w formie <i>Martina</i>.", "Majewski": "<b>Majewski</b> (forma żeńska: <b>Majewska</b>; liczba mnoga: <b>Majewscy</b>) – <a href=\"https://pl.wikipedia.org/wiki/Polskie_nazwiska\" target=\"_blank\" rel=\"noopener noreferrer\">polskie</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a>. Na początku <a href=\"https://pl.wikipedia.org/wiki/Lata_90._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">lat 90.</a> <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX wieku</a> w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> nosiło je 46 379 osób.", "Meinrad": "<b>Meinrad</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członów <i>magin</i> – \"siła, moc\" i <i>rad</i> – \"rada\". Patronem tego imienia jest św. Meinrad, mnich benedyktyński z <a href=\"https://pl.wikipedia.org/wiki/IX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IX wieku</a>.", "Moroni": "<b>Moroni</b> (<a href=\"https://pl.wikipedia.org/wiki/Alfabet_deseret\" target=\"_blank\" rel=\"noopener noreferrer\">deseret</a> rozmaicie, chociażby jako 𐐣𐐄𐐡𐐄𐐤𐐌, 𐐣𐐃𐐡𐐃𐐤𐐌, 𐐣𐐄𐐡𐐃𐐤𐐌, 𐐣𐐃𐐡𐐄𐐤𐐌 czy 𐐤𐐄𐐡𐐄𐐤𐐌) – imię męskie występujące w wyznaniach należących do <a href=\"https://pl.wikipedia.org/wiki/Ruch_%C5%9Bwi%C4%99tych_w_dniach_ostatnich\" target=\"_blank\" rel=\"noopener noreferrer\">ruchu świętych w dniach ostatnich</a> (mormonów). Pochodzi z Księgi Mormona, w której nosiły je dwie postacie. Pojawiło się w źródłach już w początkach mormonizmu. Popularne w zdominowanym przez świętych w dniach ostatnich stanie Utah. Występuje wśród wyznających mormonizm Maorysów oraz w Brazylii i Ekwadorze, jak również w praktykującym małżeństwa pluralistyczne Fundamentalistycznym Kościele Jezusa Chrystusa Świętych w Dniach Ostatnich. Znalazło odzwierciedlenie w szerszej mormońskiej kulturze. Jako imię wywiedzione z pism świętych uznawane jest za powód do dumy. Ma także wywierać pozytywny wpływ na życie duchowe noszącego je człowieka.", "Maiko": "<b>Maiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;舞妓) – uczennica szkoląca się na <a href=\"https://pl.wikipedia.org/wiki/Gejsza\" target=\"_blank\" rel=\"noopener noreferrer\">gejszę</a>. Termin <i>maiko</i> występuje tylko w <a href=\"https://pl.wikipedia.org/wiki/Kioto\" target=\"_blank\" rel=\"noopener noreferrer\">Kioto</a>. Odpowiednik maiko w <a href=\"https://pl.wikipedia.org/wiki/Tokio\" target=\"_blank\" rel=\"noopener noreferrer\">Tokio</a> to <i>hangyoku</i>.", "Modesta": "<b>Modesta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Modest\" target=\"_blank\" rel=\"noopener noreferrer\">Modest</a>. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Modesta_z_Trewiru\" target=\"_blank\" rel=\"noopener noreferrer\">św. Modesta z Trewiru</a>, benedyktynka, zm. ok. <a href=\"https://pl.wikipedia.org/wiki/680\" target=\"_blank\" rel=\"noopener noreferrer\">680</a> r.", "Melchiades": "<b>Melchiades</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, pochodzące od greckiego słowa <i>μιλτος (miltos)</i> – \"czerwona ziemia\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milcjades\" target=\"_blank\" rel=\"noopener noreferrer\">św. Melchiades (Milcjades), papież</a>.", "Mosad": "<b>Mosad</b>, właśc. <b>Instytut do spraw Wywiadu i Zadań Specjalnych</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> המוסד למודיעין ולתפקידים מיוחדים, <i>Ha-Mosad le-Modi’in u-le-Tafkidim Mejuchadim</i>) – <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">izraelska</a> agencja wywiadowcza odpowiedzialna m.in. za gromadzenie politycznych, technicznych, gospodarczych danych wywiadowczych poza granicami kraju, formalnie utworzona 1 kwietnia 1951 jako Instytut Koordynacji. Obecną nazwę nadano w 1963.", "Muriel": "<b>Muriel</b> to żeńskie imię używane w Anglii, Francji oraz Irlandii. Jest to uproszczona wersja imienia Muirghea, które po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_irlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">irlandzku</a> znaczy \"jasne (lśniące) morze\"; wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a> muir – \"morze\", i geal – \"jasny\".", "Mysław": "<b>Mysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które powstało prawdopodobnie poprzez zlanie się dwóch członów końcowych staropolskich imion: członu <i>-mysł</i> (\"myśleć\") i <i>-sław</i> (\"sława, sławić\"), kiedy świadomość ich pochodzenia zatarła się.", "Mariam": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Melchizedek": "W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> wspominany jest także w <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Psalm%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Ps</a> <a href=\"https://pl.wikipedia.org/wiki/Psalm_110\" target=\"_blank\" rel=\"noopener noreferrer\">110</a>,4. W <a href=\"https://pl.wikipedia.org/wiki/Judaizm\" target=\"_blank\" rel=\"noopener noreferrer\">judaistycznej</a> literaturze mądrościowej (hebr. <i>hazal</i>) okresu od <a href=\"https://pl.wikipedia.org/wiki/Druga_%C5%9Awi%C4%85tynia\" target=\"_blank\" rel=\"noopener noreferrer\">Drugiej Świątyni</a> aż do VI w. n.e., imię <i>Melchi-sedek</i> (hebr. מלכי־צדק) rozumiane było jako przydomek syna <a href=\"https://pl.wikipedia.org/wiki/Noe\" target=\"_blank\" rel=\"noopener noreferrer\">Noego</a>, <a href=\"https://pl.wikipedia.org/wiki/Sem_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Sema</a>.", "Minos": "Według podań był potężnym i zdolnym władcą, który sprawił, że Kreta niepodzielnie panowała w tej części <a href=\"https://pl.wikipedia.org/wiki/Morze_%C5%9Ar%C3%B3dziemne\" target=\"_blank\" rel=\"noopener noreferrer\">Morza Śródziemnego</a>. Miał ukrócić <a href=\"https://pl.wikipedia.org/wiki/Pirat\" target=\"_blank\" rel=\"noopener noreferrer\">piractwo</a> i doprowadzić do rozkwitu handlu między państwami greckimi. Był znany ze sprawiedliwości, wobec czego po śmierci został jednym z trzech sędziów w <a href=\"https://pl.wikipedia.org/wiki/Hades\" target=\"_blank\" rel=\"noopener noreferrer\">Hadesie</a> – obok <a href=\"https://pl.wikipedia.org/wiki/Ajakos\" target=\"_blank\" rel=\"noopener noreferrer\">Ajakosa</a> i swojego brata <a href=\"https://pl.wikipedia.org/wiki/Radamantys\" target=\"_blank\" rel=\"noopener noreferrer\">Radamantysa</a>. Nie jest do końca zbadane, czy Minos to imię, czy też wyraz ten oznaczał na Krecie słowo <i>król</i>. Od Minosa pochodzi pojęcie <a href=\"https://pl.wikipedia.org/wiki/Kultura_minojska\" target=\"_blank\" rel=\"noopener noreferrer\">kultury minojskiej</a>.", "Masamune": "<b>Masamune Okazaki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;岡崎 正宗&#32;<i>Okazaki Masamune</i>) – <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">japoński</a> wytwórca mieczy <a href=\"https://pl.wikipedia.org/wiki/Tachi\" target=\"_blank\" rel=\"noopener noreferrer\">tachi</a>. Znany również jako Gorō Nyūdō Masamune (五郎 入道 正宗), ur. ok. 1264, zm. 1343. Pochodził z prowincji Sagami.", "Maur": "<b>Maur</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"pochodzący z Mauretanii\" (inaczej \"Arab\") lub posiadający ciemną skórę. Istnieli liczni święci o tym imieniu m.in. <a href=\"https://pl.wikipedia.org/wiki/Maur_(ucze%C5%84_%C5%9Bw._Benedykta)\" target=\"_blank\" rel=\"noopener noreferrer\">Maur (uczeń św. Benedykta)</a>.", "Marcelina": "<b>Marcelina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Marcelin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Marcelin</a>. <b>Pochodzenie i znaczenie:</b> z łaciny: Marcellus, liczba mnoga Marcelli – plebejski, później patrycjuszowski ród rzymski, jedna z gałęzi rodu Klaudiuszów.", "Marpat": "<b>MARPAT</b> (skrót od <b>MAR</b>ine <b>PAT</b>tern) – pikselowany <a href=\"https://pl.wikipedia.org/wiki/Maskowanie_(wojsko)\" target=\"_blank\" rel=\"noopener noreferrer\">kamuflaż</a> używany przez <a href=\"https://pl.wikipedia.org/wiki/Korpus_Piechoty_Morskiej_Stan%C3%B3w_Zjednoczonych\" target=\"_blank\" rel=\"noopener noreferrer\">Korpus Piechoty Morskiej Stanów Zjednoczonych</a>, zastosowany w <a href=\"https://pl.wikipedia.org/wiki/Marine_Corps_Combat_Utility_Uniform\" target=\"_blank\" rel=\"noopener noreferrer\">Marine Corps Combat Utility Uniform</a> (MCCUU), który zastąpił Camouflage Utility Uniform. Opracowany na wzór kanadyjskiego <a href=\"https://pl.wikipedia.org/wiki/CADPAT\" target=\"_blank\" rel=\"noopener noreferrer\">CADPAT</a>'a (CAnadian Disruptive PATtern). Wzór jest tworzony przez wiele małych, prostokątnych pikseli. W teorii oznacza to, że MARPAT jest bardziej efektywny w kamuflowaniu od innych „normalnych” kamuflaży, ponieważ naśladuje cętkowane powierzchnie i zatarte granice jakie można znaleźć w naturalnym środowisku. Spowodowane jest to tym, jak ludzkie oko odbiera spikselowane obrazy. Kamuflaż MARPAT pozwala opóźnić wykrycie żołnierza około 2,5-krotnie (w porównaniu do munduru w jednolitym kolorze) lub 1,5-krotnie (w porównaniu do Eurocam). Taki kamuflaż dobrze maskuje gdy patrzy się na niego z niewielkiej odległości ale, za to gdy patrzy się na niego z większej odległości, zlewa się, tworząc dobrze rozpoznawalną plamę o kształcie człowieka. Graniczną odległością, na jakiej wzór nie zlewa się w jednolitą plamę, jest około 100 <a href=\"https://pl.wikipedia.org/wiki/Metr\" target=\"_blank\" rel=\"noopener noreferrer\">metrów</a>.", "Micius": "<b>Mo Di</b> (chiń. 墨翟) albo <b>Mozi</b> (chiń. 墨子, dosł. <b>Mistrz Mo</b>), przestarzale latynizowany także jako <b>Micjusz</b> (łac. Micius) (ur. ok. <a href=\"https://pl.wikipedia.org/wiki/480_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">480 p.n.e.</a>, zm. ok. <a href=\"https://pl.wikipedia.org/wiki/390_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">390 p.n.e.</a>) – <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">chiński</a> <a href=\"https://pl.wikipedia.org/wiki/Filozof\" target=\"_blank\" rel=\"noopener noreferrer\">filozof</a>, twórca <a href=\"https://pl.wikipedia.org/wiki/Motizm\" target=\"_blank\" rel=\"noopener noreferrer\">motizmu</a>. Swoje poglądy zawarł w księdze nazywanej od jego imienia – <i>Mozi</i>. Po nastaniu <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Cesarstwa Chińskiego</a> jego szkoła przestała istnieć, ale myśl nie została zapomniana, była jedynie przedmiotem nieustannej krytyki ze strony konfucjanistów. W XVI wieku misjonarze europejscy (jezuici) uważali Mo Di za naturalnego chrześcijanina (<i>anima naturaliter christiana</i>). Odkryto go na nowo pod koniec <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>, jego nauka stała się przedmiotem zainteresowania ideologów nacjonalizmu chińskiego (<a href=\"https://pl.wikipedia.org/wiki/Liang_Qichao\" target=\"_blank\" rel=\"noopener noreferrer\">Liang Qichao</a>), <a href=\"https://pl.wikipedia.org/wiki/Republika_Chi%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Republiki Chińskiej</a> (<a href=\"https://pl.wikipedia.org/wiki/Sun_Jat-sen\" target=\"_blank\" rel=\"noopener noreferrer\">Sun Jat-sen</a>) oraz <a href=\"https://pl.wikipedia.org/wiki/Komunizm\" target=\"_blank\" rel=\"noopener noreferrer\">komunistów</a> (proto-komunista).", "Marianna": "<b>Marianna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Marian\" target=\"_blank\" rel=\"noopener noreferrer\">Marian</a>. Potocznie jest ono często błędnie rozumiane jako wynik złożenia dwóch innych imion: <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Marii</a> i <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anny</a>, analogicznie do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Maryann</em>.", "Marcian": "Był jednym z wodzów w armii <a href=\"https://pl.wikipedia.org/wiki/Flawiusz_Ardaburiusz_Aspar\" target=\"_blank\" rel=\"noopener noreferrer\">Aspara</a>, <i>magistra militum</i>, czyli głównodowodzącego armii <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_Bizanty%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">bizantyńskiej</a>, pochodzącego z <a href=\"https://pl.wikipedia.org/wiki/Ludy_ira%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">irańskiego</a> ludu <a href=\"https://pl.wikipedia.org/wiki/Alanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Alanów</a> (stanowiło to istotną przeszkodę w objęciu przez niego tronu). Cesarzem obrano Marcjana, gdy poślubił siostrę poprzednika, <a href=\"https://pl.wikipedia.org/wiki/Pulcheria_(cesarzowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Pulcherię</a>, choć było to fikcyjne małżeństwo, a Pulcheria do końca życia pozostała dziewicą.", "Millo": "<b>Millo</b> (lub Mello) (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hbr</a>. מילוא), dosł. wypełnienie lub taras – starożytne budowle występujące w miastach izraelskich, np. <a href=\"https://pl.wikipedia.org/wiki/Sychem\" target=\"_blank\" rel=\"noopener noreferrer\">Sychem</a> bądź w <a href=\"https://pl.wikipedia.org/wiki/Jerozolima\" target=\"_blank\" rel=\"noopener noreferrer\">Jerozolimie</a>, będące prawdopodobnie rodzajem umocnionych kamieniami tarasów lub nasypów, mających cywilne znaczenie budowlane – można było na nich stawiać budynki, co w warunkach górskich jest bardzo ważne dla rozwoju miast (patrz <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_S%C4%99dzi%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Sdz</a> 9:6 i 20, <a href=\"https://pl.wikipedia.org/wiki/1_Ksi%C4%99ga_Kr%C3%B3lewska\" target=\"_blank\" rel=\"noopener noreferrer\">1 Krl</a> 9:24, <a href=\"https://pl.wikipedia.org/wiki/2_Ksi%C4%99ga_Kr%C3%B3lewska\" target=\"_blank\" rel=\"noopener noreferrer\">2 Krl</a> 20:21), albo militarne znaczenie budowlane – można było na nich postawić np. mur obronny (patrz 1 Krl 11:27).", "Maciejewski": "<b>Maciejewski</b> (forma żeńska: <b>Maciejewska</b>; liczba mnoga: <b>Maciejewscy</b>) – <a href=\"https://pl.wikipedia.org/wiki/Polskie_nazwiska\" target=\"_blank\" rel=\"noopener noreferrer\">polskie nazwisko</a>, powstałe z rdzenia „<a href=\"https://pl.wikipedia.org/wiki/Maciej\" target=\"_blank\" rel=\"noopener noreferrer\">Maciej</a>”, lub od nazw miejscowych <a href=\"https://pl.wikipedia.org/wiki/Maciej%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Maciejów</a>, Maciejewice, <a href=\"https://pl.wikipedia.org/wiki/Maciejowice\" target=\"_blank\" rel=\"noopener noreferrer\">Maciejowice</a>. Na początku <a href=\"https://pl.wikipedia.org/wiki/Lata_90._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">lat 90.</a> <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX wieku</a> w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> nosiło je 31 224 osoby.", "Mubaraka": "Imię to ma korzenie religijne i wywodzi się od arabskiego rdzenia słowotwórczego <i>b-r-k</i> (&#8207;ب ر ك&#8206;) odnoszącego się do błogosławienia. Pod względem gramatycznym jest to <a href=\"https://pl.wikipedia.org/wiki/Imies%C5%82%C3%B3w_przymiotnikowy_bierny\" target=\"_blank\" rel=\"noopener noreferrer\">imiesłów bierny</a> <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_gramatyczny\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaju żeńskiego</a> III klasy i oznacza dosłownie „błogosławiona, szczęśliwa” (a więc podobnie jak imiona łacińskie <i><a href=\"https://pl.wikipedia.org/wiki/Beata\" target=\"_blank\" rel=\"noopener noreferrer\">Beata</a></i> i <i><a href=\"https://pl.wikipedia.org/wiki/Benedykta\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykta</a></i>).", "Mannan": "<b>Mannan</b> – rodzaj <a href=\"https://pl.wikipedia.org/wiki/Polisacharyd\" target=\"_blank\" rel=\"noopener noreferrer\">polisacharydów</a> pochodzenia roślinnego zbudowanych z reszt <a href=\"https://pl.wikipedia.org/wiki/Mannoza\" target=\"_blank\" rel=\"noopener noreferrer\">mannozy</a>. Mannan w ostatnim etapie biosyntezy <a href=\"https://pl.wikipedia.org/wiki/Streptomycyna\" target=\"_blank\" rel=\"noopener noreferrer\">streptomycyny</a> indukuje działanie streptymycynazy - <a href=\"https://pl.wikipedia.org/wiki/Enzym\" target=\"_blank\" rel=\"noopener noreferrer\">enzymu</a> rozkładającego streptomycynę B (produkt uboczny) do <a href=\"https://pl.wikipedia.org/wiki/Streptomycyna\" target=\"_blank\" rel=\"noopener noreferrer\">streptomycyny A</a> (pożądany produkt - antybiotyk).", "Miłobrat": "<b>Miłobrat</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Miło-</i> (\"miły\", \"miłujący\") i <i>-brat</i> (\"brat\", \"członek wspólnoty rodowej\", \"człowiek bliski\"). Mogło oznaczać \"tego, który miłuje swoich bliskich\".", "Mashallah": "<i><b>Maszallah</b></i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مَا شَاءَ ٱللَّٰهُ&#8206;) – arabska fraza oznaczająca „Wola <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Boga</a>” lub „jak Bóg sobie życzy”. Wyraża radość, uznanie, wdzięczność lub pochwałę.", "Muhammad Iqbal": "Powrócił do <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indii</a>, aby podjąć praktykę prawniczą i został mianowany <a href=\"https://pl.wikipedia.org/wiki/Profesor\" target=\"_blank\" rel=\"noopener noreferrer\">profesorem</a> filozofii. Zdobył pozycję czołowego poety tworzącego w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_urdu\" target=\"_blank\" rel=\"noopener noreferrer\">urdu</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskim</a>. Uczestniczył w konferencjach okrągłego stołu w 1931 i 1932 roku. Był mistykiem przybierając imię <i>„Ja” i Jedności <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Boga</a></i>. Jego wykłady zebrane w tomie <i>Odbudowa religijnej myśli islamskiej</i> (org.: <i>The Reconstruction of Religious Thought in Islam</i>), wydanym w 1934 r., odegrały ważną rolę w umacnianiu wiary we własne siły wśród społeczności muzułmańskiej. W programowym przemówieniu do członków <a href=\"https://pl.wikipedia.org/wiki/Liga_Muzu%C5%82ma%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Ligi Muzułmańskiej</a>, której był aktywnym działaczem, podczas jej konferencji w <a href=\"https://pl.wikipedia.org/wiki/Prajagrad%C5%BA\" target=\"_blank\" rel=\"noopener noreferrer\">Allahabadzie</a>, przedstawił koncepcję oddzielnego <a href=\"https://pl.wikipedia.org/wiki/Pa%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">państwa</a> muzułmańskiego, o charakterze <a href=\"https://pl.wikipedia.org/wiki/Republika_islamska\" target=\"_blank\" rel=\"noopener noreferrer\">republiki islamskiej</a>, w północno-zachodnich Indiach. W kwestii tej dyskutował m.in. z <a href=\"https://pl.wikipedia.org/wiki/Mahatma_Gandhi\" target=\"_blank\" rel=\"noopener noreferrer\">Mahatmą Gandhim</a>. Doczekała się ona jednak realizacji dopiero 9 lat po jego śmierci w postaci państwowości <a href=\"https://pl.wikipedia.org/wiki/Pakistan\" target=\"_blank\" rel=\"noopener noreferrer\">pakistańskiej</a>.", "Manga": "<b>Manga</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;漫画&#59; wymowa (<a href=\"https://pl.wikipedia.org/wiki/IPA\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>): <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">m</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_tylnoj%C4%99zykowo-mi%C4%99kkopodniebienna_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ŋ</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">g</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>) – komiks, obraz, rysunek, szkic, <a href=\"https://pl.wikipedia.org/wiki/Karykatura\" target=\"_blank\" rel=\"noopener noreferrer\">karykatura</a>. Japońskie słowo wywodzące się ze sposobu ozdabiania <a href=\"https://pl.wikipedia.org/wiki/Rycina\" target=\"_blank\" rel=\"noopener noreferrer\">rycin</a> i innych form <a href=\"https://pl.wikipedia.org/wiki/Sztuka_u%C5%BCytkowa\" target=\"_blank\" rel=\"noopener noreferrer\">sztuki użytkowej</a>. Współcześnie używane poza <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonią</a> oznacza japoński <a href=\"https://pl.wikipedia.org/wiki/Komiks\" target=\"_blank\" rel=\"noopener noreferrer\">komiks</a>.", "Mszczuj": "<b>Mszczuj</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, najprawdopodobniej wariant imienia <a href=\"https://pl.wikipedia.org/wiki/M%C5%9Bciwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Mściwuj</a>.", "Małgorzata": "<b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Marzena": "<b>Marzena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które powstało najprawdopodobniej jako zdrobnienie <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a> lub <a href=\"https://pl.wikipedia.org/wiki/Marzanna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Marzanny</a>. Istnieje możliwość, że zdrabniano tak <a href=\"https://pl.wikipedia.org/wiki/Marta_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Martę</a> lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Marię</a>.", "Mariola": "<b>Mariola</b> – imię żeńskie. Pierwotnie było zdrobnieniem od imienia <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> lub skrótem od podwójnego imienia Maria Jolanta. Obecnie stanowi odrębne imię. Występuje przede wszystkim w Polsce.", "Mirosława": "<b>Mirosława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członów <i>Miro-</i> (<i>pokój</i>, <i>spokój</i>, <i>dobro</i>) oraz <i>-sława</i> (<i>sława</i>). Mogło oznaczać <i>ta, która sławi pokój</i>. W źródłach polskich poświadczone od <a href=\"https://pl.wikipedia.org/wiki/1222\" target=\"_blank\" rel=\"noopener noreferrer\">1222</a> roku. <a href=\"https://pl.wikipedia.org/wiki/Anagram\" target=\"_blank\" rel=\"noopener noreferrer\">Anagram</a> tego imienia też jest żeńskim imieniem – <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomira\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomira</a>.", "Milena": "<b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Michalina": "<b>Michalina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Michał</a>. Oznacza „któż [jest] jak Bóg”. Imię to nadawane jest w tej formie w Polsce przynajmniej od <a href=\"https://pl.wikipedia.org/wiki/1744\" target=\"_blank\" rel=\"noopener noreferrer\">1744</a> roku, natomiast już w średniowieczu notowano jako żeński odpowiednik Michała formę <i><b>Michaelis</b></i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>), zdrobniale – Michałka. Wśród imion nadawanych nowo narodzonym dzieciom, Michalina w 2018 r. zajmowała 24. miejsce w grupie imion żeńskich.", "Marlena": "<b>Marlena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, formowane na dwa sposoby:", "Malwina": "<b>Malwina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia celtyckiego lub germańskiego. Imię to może pochodzić od galickiego imienia Malamhin składającego się ze słów mala mhinn – „gładkie czoło” lub z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a>: mahal – „sąd, sprawiedliwość” oraz wini „przyjaciel”, można więc przetłumaczyć je jako „strzegąca praw, prawowierna”. W XVIII wieku szkocki poeta <a href=\"https://pl.wikipedia.org/wiki/James_Macpherson\" target=\"_blank\" rel=\"noopener noreferrer\">James Macpherson</a> użył je w tzw. <i>pieśniach <a href=\"https://pl.wikipedia.org/wiki/Osjan_(Macpherson)\" target=\"_blank\" rel=\"noopener noreferrer\">Osjana</a></i> – Malwina była narzeczoną Oskara, syna Osjana. Poezję osjaniczną przełożył na język polski m.in. <a href=\"https://pl.wikipedia.org/wiki/Ignacy_Krasicki\" target=\"_blank\" rel=\"noopener noreferrer\">Ignacy Krasicki</a>. W literaturze polskiej wykorzystał to imię <a href=\"https://pl.wikipedia.org/wiki/Ludwik_Kropi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Ludwik Kropiński</a> w utworze <i>Miłość malująca obraz Malwiny</i>, a w romansie sentymentalnym <i><a href=\"https://pl.wikipedia.org/wiki/Malwina,_czyli_domy%C5%9Blno%C5%9B%C4%87_serca\" target=\"_blank\" rel=\"noopener noreferrer\">Malwina, czyli domyślność serca</a></i> <a href=\"https://pl.wikipedia.org/wiki/Maria_Wirtemberska\" target=\"_blank\" rel=\"noopener noreferrer\">Maria z Czartoryskich Wirtemberska</a>. Literatura i media przyczyniły się do wzrostu popularności imienia.", "Matylda": "<b>Matylda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka staro-wysoko-niemieckiego</a> – słów <i>maht</i> (potęga, władza) oraz <i>hild(is)</i> (walka). Tłumaczy się jako „ta, która jest silna, odważna w walce”.", "Magda": "<b>Magda</b> – zdrobnienie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Magdalena</a>. Występuje jednak również w Polsce jako samodzielne imię, pomimo prawnego zakazu nadawania imion w formie zdrobniałej.", "Mieczysława": "<b>Mieczysława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Mieczys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Mieczysław</a>. Patronką tego imienia jest bł. <a href=\"https://pl.wikipedia.org/wiki/Mieczys%C5%82awa_Kowalska\" target=\"_blank\" rel=\"noopener noreferrer\">Mieczysława Kowalska</a>, jedna ze <a href=\"https://pl.wikipedia.org/wiki/108_b%C5%82ogos%C5%82awionych_m%C4%99czennik%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">108 błogosławionych męczenników</a> II wojny światowej.", "Marika": "<b>Marika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia „<a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a>”. Jest <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">węgierską</a> formą tego imienia, chociaż znane jest także w Bułgarii i na terenie byłej Jugosławii. Imię jest również zniemczoną formą zdrobnienia „Maryjka” występującego w <a href=\"https://pl.wikipedia.org/wiki/Etnolekt_%C5%9Bl%C4%85ski\" target=\"_blank\" rel=\"noopener noreferrer\">etnolekcie śląskim</a>.", "Marzanna": "Imię bogini wywodzone jest z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_praindoeuropejski\" target=\"_blank\" rel=\"noopener noreferrer\">praindoeuropejskiego</a> rdzenia <i>*mar-</i>, <i>*mor-</i>, oznaczającego śmierć. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacka</a> forma <a href=\"https://pl.wikipedia.org/wiki/Teonim\" target=\"_blank\" rel=\"noopener noreferrer\">teonimu</a> <i>Ma(r)muriena</i> sugeruje ewentualne związki z <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsem</a> (Marmorem, Mamersem, Mamuriusem Veturiusem). Śmierć Marzanny wraz z końcem zimy przeciwstawia ją symbolizującemu wiosnę <a href=\"https://pl.wikipedia.org/wiki/Jary%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">Jaryle</a>, który rodził się wraz z nadejściem wiosny&#8201;.", "Melania": "<b>Melania</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μέλας, znaczącego „czarna”.", "Marcela": "<b>Marcela</b> – imię żeńskie, odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> męskiego <a href=\"https://pl.wikipedia.org/wiki/Marceli\" target=\"_blank\" rel=\"noopener noreferrer\">Marceli</a>.", "Mirela": "<b>Mirela</b>, <b>Mirella</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_prowansalski\" target=\"_blank\" rel=\"noopener noreferrer\">dialektu prowansalskiego</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_oksyta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka oksytańskiego</a>, od imienia <i>Mirèio</i>. Zostało ono użyte po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/Mirejo\" target=\"_blank\" rel=\"noopener noreferrer\">jednym z poematów</a> przez poetę <a href=\"https://pl.wikipedia.org/wiki/Fr%C3%A9d%C3%A9ric_Mistral\" target=\"_blank\" rel=\"noopener noreferrer\">Frédérica Mistrala</a>, który wywiódł <i>Mirèio</i> prawdopodobnie od słowa <i>mirar</i>, w dialekcie <a href=\"https://pl.wikipedia.org/wiki/Prowansja\" target=\"_blank\" rel=\"noopener noreferrer\">prowansalskim</a> oznaczającego „podziwiana” (z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>mirare</i> „podziwiać”). Mirela może także stanowić skrócenie włoskiego imienia <i>Mirabella</i>.", "Maryla": "<b>Maryla</b> – forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> pochodząca od romańskiego zdrobnienia pierwowzoru.", "Marina": "Imię Maryna jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Maryn\" target=\"_blank\" rel=\"noopener noreferrer\">Maryn</a>, w Polsce niezwykle rzadkim (w 1994 roku nosiła je jedna osoba, w roku 2001 – 203 osoby, zaś w wariancie <i>Marina</i> – 362). Imię to wywodzi się od imienia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Marinus</em>, a to z kolei powstało z przymiotnika <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>marinus</em> („morski”). Imię Maryna – rozumiane jako żeński odpowiednik imienia Maryn – poświadczone jest w Polsce już w XV wieku (najwcześniej w 1443 roku). Zdrobnienie od niego brzmi Marynia. Marina to cudzoziemski wariant imienia Maryna; trudno powiedzieć, skąd przybyło do Polski, z uwagi na podobną formę w prawie wszystkich językach europejskich.", "Mirella": "<b>Mirela</b>, <b>Mirella</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_prowansalski\" target=\"_blank\" rel=\"noopener noreferrer\">dialektu prowansalskiego</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_oksyta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka oksytańskiego</a>, od imienia <i>Mirèio</i>. Zostało ono użyte po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/Mirejo\" target=\"_blank\" rel=\"noopener noreferrer\">jednym z poematów</a> przez poetę <a href=\"https://pl.wikipedia.org/wiki/Fr%C3%A9d%C3%A9ric_Mistral\" target=\"_blank\" rel=\"noopener noreferrer\">Frédérica Mistrala</a>, który wywiódł <i>Mirèio</i> prawdopodobnie od słowa <i>mirar</i>, w dialekcie <a href=\"https://pl.wikipedia.org/wiki/Prowansja\" target=\"_blank\" rel=\"noopener noreferrer\">prowansalskim</a> oznaczającego „podziwiana” (z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>mirare</i> „podziwiać”). Mirela może także stanowić skrócenie włoskiego imienia <i>Mirabella</i>.", "Manuela": "<b>Manuela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i><b>Manuel</b></i>, będącego skróconą formą biblijnego imienia <a href=\"https://pl.wikipedia.org/wiki/Emanuel\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuel</a>. Manuela jest skróconą formą imienia <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Marcjanna": "<b>Marcjana</b>, również <b>Marcjanna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Marcjan\" target=\"_blank\" rel=\"noopener noreferrer\">Marcjan</a>. Wśród świętych m.in. św. Marcjana z Cezarei Mauretańskiej.", "Marietta": "<b>Marietta</b>, <i>Marieta</i> – imię zapożyczone z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">języka włoskiego</a>, w którym funkcjonuje jako zdrobnienie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> lub jako imię nadawane samodzielnie.", "Malina": "<b>Malina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które prawdopodobnie jest zdrobnieniem imienia <a href=\"https://pl.wikipedia.org/wiki/Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Magdalena</a>, powstałym na gruncie kilku języków wschodniosłowiańskich bądź w Skandynawii. <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> ma wątpliwości dotyczące nadawania tego imienia ludziom.", "Melisa": "<b>Melisa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznacza „pszczołę” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μέλισσα). W <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiej mitologii</a> Melissa była jedną z <a href=\"https://pl.wikipedia.org/wiki/Nimfy\" target=\"_blank\" rel=\"noopener noreferrer\">nimf</a> opiekujących się małym <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusem</a>.", "Marita": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Margareta": "<b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Miłosława": "<b>Miłosława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członów <i>Miło-</i> („miły”, „miłujący”) i <i>-sława</i> („sława”). Znaczenie imienia: „miła sławie”. Poświadczone w źródłach polskich jako Miłosława (XII wiek) i Miełosława (XIII–XIV wiek).", "Mercedes": "Od imienia <a href=\"https://pl.wikipedia.org/wiki/Merc%C3%A9d%C3%A8s_Jellinek\" target=\"_blank\" rel=\"noopener noreferrer\">Mercédès Jellinek</a>, córki <a href=\"https://pl.wikipedia.org/wiki/Emil_Jellinek\" target=\"_blank\" rel=\"noopener noreferrer\">Emila Jellinka</a>, generalnego przedstawiciela firmy <a href=\"https://pl.wikipedia.org/wiki/Daimler-Motoren-Gesellschaft\" target=\"_blank\" rel=\"noopener noreferrer\">Daimler</a>, pochodzi nazwa marki samochodów <a href=\"https://pl.wikipedia.org/wiki/Mercedes-Benz\" target=\"_blank\" rel=\"noopener noreferrer\">Mercedes</a>. W Polsce bardzo rzadko używane ze względu na spółgłoskowy wygłos oraz fakt, iż wyraz ten bardziej znany jest jako marka samochodu (i powszechnie postrzegany jako posiadający rodzaj męski), niż imię żeńskie.", "Mirona": "<b>Mirona</b> – żeński odpowiednik pochodzącego z języka greckiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Miron\" target=\"_blank\" rel=\"noopener noreferrer\">Miron</a>.", "Marysia": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maura": "<b>Maura</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Maur_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Maur</a>. W językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_szkocki_gaelicki\" target=\"_blank\" rel=\"noopener noreferrer\">szkockim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_irlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">irlandzkim</a> istnieje imię o identycznym brzmieniu, a wywodzone jest od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a> słowa <i>mór</i> oznaczającego wielki, wspaniały. W angielskim używany także jako zdrobniona forma irlandzkiej formy imienia <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – <i>Maire</i> (wymawiane <i>Moira</i>). Istnieje kilka świętych katolickich o tym imieniu.", "Maksymiliana": "<b>Maksymiliana</b>, <b>Maksymilianna</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Maksymilian\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymilian</a>. Imiona te pochodzą od nazwiska rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a>.", "Milada": "<b>Miłosława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członów <i>Miło-</i> („miły”, „miłujący”) i <i>-sława</i> („sława”). Znaczenie imienia: „miła sławie”. Poświadczone w źródłach polskich jako Miłosława (XII wiek) i Miełosława (XIII–XIV wiek).", "Miła": "<b>Miła</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia słowiańskiego.", "Mirra": "<b>Mirra</b>, mira – wonna <a href=\"https://pl.wikipedia.org/wiki/%C5%BBywica\" target=\"_blank\" rel=\"noopener noreferrer\">żywica</a> otrzymywana z drzew i krzewów należących do rodzaju <a href=\"https://pl.wikipedia.org/wiki/Balsamowiec\" target=\"_blank\" rel=\"noopener noreferrer\">balsamowiec</a> (<i>Commiphora</i>). Uważa się, że najlepsza pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Balsamowiec_mirra\" target=\"_blank\" rel=\"noopener noreferrer\">balsamowca mirry</a> (<i>Commiphora abyssinica</i>), możliwe jest jednak uzyskiwanie jej również z innych gatunków balsamowca, np. <i><a href=\"https://pl.wikipedia.org/wiki/Commiphora_kataf\" target=\"_blank\" rel=\"noopener noreferrer\">Commiphora kataf</a></i> i <i><a href=\"https://pl.wikipedia.org/wiki/Commiphora_myrrha\" target=\"_blank\" rel=\"noopener noreferrer\">Commiphora myrrha</a></i>. Nazwa <i>mirra</i> wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">języków semickich</a>, por. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aram.</a>&#160;&#8207;ܡܪܝܪܐ&#8206; <i>murr</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مر&#8206; <i>murr</i> (w obydwu językach: „gorzka”; to słowo wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/Praj%C4%99zyk\" target=\"_blank\" rel=\"noopener noreferrer\">prasemickiego</a> <a href=\"https://pl.wikipedia.org/wiki/Rdze%C5%84_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">rdzenia</a> <i>m-r-r</i>). W hebrajskiej <i><a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a></i> opisana jest słowem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מוֹר&#8206; <i>môr</i> (lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מֹר&#8206; <i>mōr</i>).", "Masza": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Magdalena": "<b>Maria Magdalena</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Μαρία ἡ Μαγδαληνή), także <b>Maria z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a></b> – według <a href=\"https://pl.wikipedia.org/wiki/Ewangelia\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelii</a> żyjąca w I wieku kobieta pochodząca z wioski <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdala</a> (Magdallah lub Migdal), obecnie <a href=\"https://pl.wikipedia.org/wiki/Migdal\" target=\"_blank\" rel=\"noopener noreferrer\">Migdal</a>. Należała do kręgu uczniów <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>, przyłączyła się do niego po tym, gdy wypędził z niej siedem złych duchów.", "Mirabella": "<b>Mirabella</b> - współcześnie powstałe <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, początkowo używane w krajach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\"> francusko</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskojęzycznych</a> jako <i>Mirabelle</i>, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> słowa <i>mirabilis</i> oznaczającego \"wspaniały\".", "Madlena": "<b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Mirjam": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Macieja": "<b>Macieja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Maciej\" target=\"_blank\" rel=\"noopener noreferrer\">Maciej</a>. Patronką tego imienia jest bł. <a href=\"https://pl.wikipedia.org/wiki/Macieja_Nazzarei\" target=\"_blank\" rel=\"noopener noreferrer\">Macieja Nazzarei</a>, klaryska (zm. ok. 1320).", "Matea": "<b>Matea</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Mateusz\" target=\"_blank\" rel=\"noopener noreferrer\">Mateusz</a>. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> rzadko używana.", "Morena": "<b>Morena:</b> 1. Wszelki materiał skalny składający się z przemieszanych <a href=\"https://pl.wikipedia.org/wiki/Frakcja_(geologia)\" target=\"_blank\" rel=\"noopener noreferrer\">frakcji</a> różnej wielkości (bloki skalne, <a href=\"https://pl.wikipedia.org/wiki/G%C5%82az\" target=\"_blank\" rel=\"noopener noreferrer\">głazy</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%BBwir\" target=\"_blank\" rel=\"noopener noreferrer\">żwiry</a>, <a href=\"https://pl.wikipedia.org/wiki/Piasek\" target=\"_blank\" rel=\"noopener noreferrer\">piaski</a>, <a href=\"https://pl.wikipedia.org/wiki/Py%C5%82_(ska%C5%82a)\" target=\"_blank\" rel=\"noopener noreferrer\">pyły</a>), <a href=\"https://pl.wikipedia.org/wiki/Glina\" target=\"_blank\" rel=\"noopener noreferrer\">gliny</a>, transportowanych i osadzanych przez lodowiec, pochodzących głównie z niszczenia jego podłoża, ze zboczy wznoszących się ponad powierzchnię lodowca, jak również przynoszonych przez <a href=\"https://pl.wikipedia.org/wiki/Lawina\" target=\"_blank\" rel=\"noopener noreferrer\">lawiny</a> i wiatr.", "Marga": "Chrząszcze o wydłużonym ciele. Głowę mają owalną lub okrągławą, węższą od <a href=\"https://pl.wikipedia.org/wiki/Przedplecze\" target=\"_blank\" rel=\"noopener noreferrer\">przedplecza</a>, o <a href=\"https://pl.wikipedia.org/wiki/Skro%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">skroniach</a> od spodu zwykle odgraniczonych ostrą listewką, a oczach różnych rozmiarów. Znajdujące się na głowie punkty <a href=\"https://pl.wikipedia.org/wiki/Czo%C5%82o_(anatomia)\" target=\"_blank\" rel=\"noopener noreferrer\">czołowe</a>, ciemieniowe i skroniowe są istotne w <a href=\"https://pl.wikipedia.org/wiki/Oznaczanie_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">oznaczaniu</a>. Paciorkowate czułki mają pierwszy człon krótszy niż dwa następne razem wzięte. Aparat gębowy cechują <a href=\"https://pl.wikipedia.org/wiki/Warga_g%C3%B3rna\" target=\"_blank\" rel=\"noopener noreferrer\">warga górna</a> o przedniej krawędzi wykrojonej, niewykrojonej lub wciętej, <a href=\"https://pl.wikipedia.org/wiki/%C5%BBuwaczka\" target=\"_blank\" rel=\"noopener noreferrer\">żuwaczki</a> z jednym lub dwoma zębami na krawędziach wewnętrznych, ostatni człon głaszczków szczękowych nie krótszy i węższy od poprzedniego, zaostrzony lub wrzecionowaty u szczytu, a ostatni człon krótkich <a href=\"https://pl.wikipedia.org/wiki/G%C5%82aszczki_wargowe\" target=\"_blank\" rel=\"noopener noreferrer\">głaszczków wargowych</a> stożkowaty lub wrzecionowaty i dłuższy od poprzedniego. <a href=\"https://pl.wikipedia.org/wiki/Przedtu%C5%82%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Przedtułów</a> cechuje się <a href=\"https://pl.wikipedia.org/wiki/Skleryt\" target=\"_blank\" rel=\"noopener noreferrer\">zesklerotyzowanymi</a> epimerami trójkątnego kształtu. <a href=\"https://pl.wikipedia.org/wiki/Przedplecze\" target=\"_blank\" rel=\"noopener noreferrer\">Przedplecze</a> zwykle ma dwa grzbietowe rzędy po 2–4 punkty oraz parę dużych punktów przy brzegach bocznych, zaś jego <a href=\"https://pl.wikipedia.org/wiki/Epipleury\" target=\"_blank\" rel=\"noopener noreferrer\">epipleury</a> są podwinięte na spód i z boku niewidoczne. Przednia para odnóży ma u obu płci rozszerzone <a href=\"https://pl.wikipedia.org/wiki/Stopa_sze%C5%9Bcionog%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">stopy</a>.", "Mścisława": "<b>Mścisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z dwóch członów: <i>Mści-</i> (\"mścić\") i <i>-sława</i> (\"sława\"). Mogło oznaczać \"tę, która zdobywa sławę mszcząc się na swych wrogach\". Poświadczone w źródłach jako Mścisława (1360) i formach zdrobniałych Mścicha (1394), Mścichna (1383).", "Morgana": "Przedstawiana zawsze jako obdarzona wielką mocą czarodziejka, żeński odpowiednik Merlina i jego mocy, w niektórych wersjach legendy działa przeciwko królowi Arturowi i jego żonie <a href=\"https://pl.wikipedia.org/wiki/Ginewra\" target=\"_blank\" rel=\"noopener noreferrer\">Ginewrze</a>. W <i><a href=\"https://pl.wikipedia.org/wiki/%C5%9Amier%C4%87_Artura\" target=\"_blank\" rel=\"noopener noreferrer\">Le Morte d’Arthur</a></i> <a href=\"https://pl.wikipedia.org/wiki/Thomas_Malory\" target=\"_blank\" rel=\"noopener noreferrer\">Thomasa Malory’ego</a> jest nieszczęśliwą żoną króla Uriena, spiskującą przeciwko Arturowi i pragnącą zapewnić władzę swojemu ukochanemu Akkolonowi.", "Mariko": "<b>Mariko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まりこ, マリコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Miłochna": "<b>Miłochna</b> – forma pochodna (zdrobnienie) od staropolskich <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imion</a> żeńskich rozpoczynających się na <i>Miło-</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosława</a>. Poświadczone w źródłach polskich od XIII wieku (1265 rok).", "Miho": "<b>Miho</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みほ, ミホ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Mayumi": "<b>Mayumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まゆみ, マユミ) – głównie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, rzadko noszone przez mężczyzn.", "Medarda": "<b>Medarda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Medard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Medard</a>, powstałego z członów <i>maht</i> — \"potęga, władza, moc, męstwo\" oraz <i>hart</i> — \"silny, odważny, śmiały\".", "Mili": "<b>mili</b> (<b>m</b>) – przedrostek <a href=\"https://pl.wikipedia.org/wiki/Jednostka_miary\" target=\"_blank\" rel=\"noopener noreferrer\">jednostki</a> <a href=\"https://pl.wikipedia.org/wiki/Miara_(metrologia)\" target=\"_blank\" rel=\"noopener noreferrer\">miary</a> oznaczający mnożnik 0,001 = 10 (jedna tysięczna).", "Maurycja": "<b>Maurycja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imion <a href=\"https://pl.wikipedia.org/wiki/Maurycy\" target=\"_blank\" rel=\"noopener noreferrer\">Maurycy</a> i <a href=\"https://pl.wikipedia.org/wiki/Maurycjusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Maurycjusz</a>. Wywodzi się od słowa oznaczającego „pochodząca z Mauretanii”, „Maur”.", "Meredith": "<b>Meredith</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_walijski\" target=\"_blank\" rel=\"noopener noreferrer\">walijskiego</a>, początkowo męskie, od imienia Maredudd – \"wielki pan\"; w XX wieku używane również jako imię żeńskie. Występuje też jako <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a>.", "Megumi": "<b>Megumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;めぐみ, メグミ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Miyuki": "<b>Miyuki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みゆき, ミユキ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Maksymilianna": "<b>Maksymiliana</b>, <b>Maksymilianna</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Maksymilian\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymilian</a>. Imiona te pochodzą od nazwiska rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a>.", "Midori": "<b>Midori</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みどり, ミドリ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Melia": "Była córką <a href=\"https://pl.wikipedia.org/wiki/Okeanos\" target=\"_blank\" rel=\"noopener noreferrer\">Okeanosa</a>. Została kochanką boga <a href=\"https://pl.wikipedia.org/wiki/Apollo\" target=\"_blank\" rel=\"noopener noreferrer\">Apollina</a>, z którym spłodziła Ismeniosa i Temerosa. Czczono ją wraz z Apollinem w świątyni koło <a href=\"https://pl.wikipedia.org/wiki/Teby_(Grecja)\" target=\"_blank\" rel=\"noopener noreferrer\">Tebami</a>. Jej imieniem nazwano też źródło w samych Tebach. Niektóre źródła podają, że wśród <a href=\"https://pl.wikipedia.org/wiki/Okeanidy\" target=\"_blank\" rel=\"noopener noreferrer\">okeanid</a> była też inna Melia, małżonka boga rzeki <a href=\"https://pl.wikipedia.org/wiki/Inachos\" target=\"_blank\" rel=\"noopener noreferrer\">Inachos</a>.", "Malwa": "<b>Malwa</b>, topolówka (<i>Alcea</i> <a href=\"https://pl.wikipedia.org/wiki/Karol_Linneusz\" target=\"_blank\" rel=\"noopener noreferrer\">L.</a>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/%C5%9Alazowate\" target=\"_blank\" rel=\"noopener noreferrer\">ślazowatych</a>. Podawanych jest z niego ok. 60, 70, 80 <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunków</a>. Pochodzą one głównie ze wschodniej części basenu Morza Śródziemnego (tylko w <a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">Turcji</a> rośnie 18 gatunków). Poza tym rosną w południowej i wschodniej Europie oraz południowo-zachodniej i centralnej Azji. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> jako przejściowo dziczejącą (<a href=\"https://pl.wikipedia.org/wiki/Efemerofit\" target=\"_blank\" rel=\"noopener noreferrer\">efemerofit</a>) stwierdzono tylko malwę pomarszczoną <i>A. rugosa</i>. W naturze przedstawiciele tego rodzaju rosną na suchych, często skalistych siedliskach.", "Mamerta": "<b>Mamerta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_italskie\" target=\"_blank\" rel=\"noopener noreferrer\">italskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Mamert\" target=\"_blank\" rel=\"noopener noreferrer\">Mamert</a>, wywodzącego się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_oskijski\" target=\"_blank\" rel=\"noopener noreferrer\">oskijskiego</a> lub sabińskiego wariantu imienia boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a> – <i>Mamers</i>, który w przypadkach zależnych (np. <i>Mamertis</i>) miał temat <i>Mamert</i>.", "Michiko": "<b>Michiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みちこ, ミチコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Masako": "W dniu 22 października 2019 jej małżonek, cesarz Naruhito, formalnie ogłosił swoją intronizację oraz przyjął gratulacje od przedstawicieli narodu japońskiego i licznych gości zagranicznych. Główna ceremonia intronizacji o nazwie „Sokuirei-Seiden-no-gi” odbyła się w Pałacu Cesarskim w Tokio.", "Misaki": "<b>Misaki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みさき, ミサキ) – popularne żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, jest także używane jako nazwisko, bardzo rzadko używane jako imię męskie.", "Maarit": "<b>Maarit Helena Hurmerinta</b> (z domu <b>Äijö</b>, ur. <a href=\"https://pl.wikipedia.org/wiki/10_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">10 listopada</a> <a href=\"https://pl.wikipedia.org/wiki/1953\" target=\"_blank\" rel=\"noopener noreferrer\">1953</a> w <a href=\"https://pl.wikipedia.org/wiki/Helsinki\" target=\"_blank\" rel=\"noopener noreferrer\">Helsinkach</a>) jest fińską <a href=\"https://pl.wikipedia.org/wiki/%C5%9Apiew\" target=\"_blank\" rel=\"noopener noreferrer\">piosenkarką</a> i <a href=\"https://pl.wikipedia.org/wiki/Muzyk\" target=\"_blank\" rel=\"noopener noreferrer\">muzykiem</a>. Występuje pod imieniem <b>Maarit</b>.", "Małgosia": "<b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Mami": "<b>Mami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まみ, マミ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Miwa": "<b>Miwa</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みわ, ミワ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, może być używane jako nazwisko.", "Manami": "<b>Manami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まなみ, マナミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Moe": "Postacie będące źródłem tej reakcji, zwane „postaciami <i>moe</i>”&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;萌えキャラ&#32;<i>moe kyara</i>), pochodzą najczęściej z <a href=\"https://pl.wikipedia.org/wiki/Manga\" target=\"_blank\" rel=\"noopener noreferrer\">mang</a> i <a href=\"https://pl.wikipedia.org/wiki/Anime\" target=\"_blank\" rel=\"noopener noreferrer\">anime</a>, a także gier i powieści zawierających ilustracje w tym stylu. W ich projektach determinującą rolę odgrywa obecność czynników afektywnych, „czynników <i>moe</i>”&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;萌え要素&#32;<i>moe yōso</i>), rozpoznawalnych w kulturze <a href=\"https://pl.wikipedia.org/wiki/Otaku\" target=\"_blank\" rel=\"noopener noreferrer\">otaku</a> – są to zarówno atrybuty wizualne, np. kocie uszy, strój pokojówki i zielone włosy, jak i inne cechy, takie jak osobowość, sposób mówienia, zawód czy sytuacja, w jakiej postać się znajduje.", "Mojmira": "<b>Mojmira</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Mojmir_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Mojmir</a>. Znaczenie imienia: \"mój pokój\", \"mój skarb\". W tej formie imię nienotowane w źródłach staropolskich.", "Momoko": "<b>Momoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;桃子,百子,ももこ,モモコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Miyu": "<b>Miyu</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みゆ, ミユ) – głównie żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, bardzo rzadko noszone przez mężczyzn.", "Melba": "<b>Melba</b> (fr. <i>pêche(s) Melba</i>, ang. <i>Peach Melba</i>) – <a href=\"https://pl.wikipedia.org/wiki/Deser\" target=\"_blank\" rel=\"noopener noreferrer\">deser</a> przygotowywany ze świeżych <a href=\"https://pl.wikipedia.org/wiki/Brzoskwinia_zwyczajna\" target=\"_blank\" rel=\"noopener noreferrer\">brzoskwiń</a>, <a href=\"https://pl.wikipedia.org/wiki/Lody\" target=\"_blank\" rel=\"noopener noreferrer\">lodów waniliowych</a> i słodzonego przecieru truskawkowego (względnie malinowego), znanego jako <b>sos melba</b> (<i>sauce Melba</i>). Przepis opracował <a href=\"https://pl.wikipedia.org/wiki/Auguste_Escoffier\" target=\"_blank\" rel=\"noopener noreferrer\">Auguste Escoffier</a>, reformator i kodyfikator <a href=\"https://pl.wikipedia.org/wiki/Kuchnia_francuska\" target=\"_blank\" rel=\"noopener noreferrer\">kuchni francuskiej</a>, na cześć australijskiej śpiewaczki <a href=\"https://pl.wikipedia.org/wiki/Nellie_Melba\" target=\"_blank\" rel=\"noopener noreferrer\">Nellie Melby</a>. Dokładniejsze informacje o jego powstaniu mają przy tym często charakter anegdotyczny – rozmijają się nawet relacje samych Escoffiera i Melby. Istnieją także inne dania nazwane imieniem Melby i kojarzone z Escoffierem, jak starsze niż melba <b>pêches au cygne</b> wzorowane na łabędziu z <i><a href=\"https://pl.wikipedia.org/wiki/Lohengrin_(opera)\" target=\"_blank\" rel=\"noopener noreferrer\">Lohengrina</a></i>, a także odmiany oryginalnej melby, w tym <b>poires Melba</b> (gruszki melba) i <b>fraises Melba</b> (truskawki melba). Znane są też tosty melba (<i>Melba toasts</i>), a także rodzaj <a href=\"https://pl.wikipedia.org/wiki/Garnirowanie\" target=\"_blank\" rel=\"noopener noreferrer\">garnirunku</a> z pomidorów o tej nazwie.", "Momina": "Od 30 maja 2010 roku zespół szkół w Mominie nosi imię mjr. Jana Piwnika „Ponurego”. Momina znajduje się także na liście miejscowości <i>Szlaków tysiąclecia po Ziemi Kieleckiej</i> <a href=\"https://pl.wikipedia.org/wiki/Wojew%C3%B3dztwo_%C5%9Bwi%C4%99tokrzyskie\" target=\"_blank\" rel=\"noopener noreferrer\">świętokrzyskiego</a> oddziału <a href=\"https://pl.wikipedia.org/wiki/Polskie_Towarzystwo_Turystyczno-Krajoznawcze\" target=\"_blank\" rel=\"noopener noreferrer\">PTTK</a> z 1966 roku.", "Madoka": "<b>Madoka</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まどか, マドカ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, może być używane jako nazwisko.", "Minjung": "Król Goguryeo <b>Minjung</b> (? – 48) – czwarty król <a href=\"https://pl.wikipedia.org/wiki/Goguryeo\" target=\"_blank\" rel=\"noopener noreferrer\">Goguryeo</a>, największego spośród <a href=\"https://pl.wikipedia.org/wiki/Trzy_Kr%C3%B3lestwa_Korei\" target=\"_blank\" rel=\"noopener noreferrer\">Trzech Królestw Korei</a>. Panował w latach 44-48. Był piątym synem drugiego władcy króla <a href=\"https://pl.wikipedia.org/wiki/Yuri_(w%C5%82adca_Goguryeo)\" target=\"_blank\" rel=\"noopener noreferrer\">Yuriego</a>. Informacje o jego życiu pochodzą głównie z koreańskich kronik <a href=\"https://pl.wikipedia.org/wiki/Samguk_Sagi\" target=\"_blank\" rel=\"noopener noreferrer\">Samguk Sagi</a> i <a href=\"https://pl.wikipedia.org/wiki/Samguk_Yusa\" target=\"_blank\" rel=\"noopener noreferrer\">Samguk Yusa</a>.", "Marcjana": "<b>Marcjana</b>, również <b>Marcjanna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Marcjan\" target=\"_blank\" rel=\"noopener noreferrer\">Marcjan</a>. Wśród świętych m.in. św. Marcjana z Cezarei Mauretańskiej.", "Maruta": "<b>Maruta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pierwotnie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Persowie\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>, oznaczające \"boża posłanka\". Patronem tego imienia jest św. Marut z Mezopotamii.", "Mutsumi": "<b>Mutsumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;むつみ, ムツミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, użwane także jako nazwisko, rzadko używane jako imię męskie.", "Minerwa": "<b>Minerwa</b> (łac. <i>Minerva</i>) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii rzymskiej</a> pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Bogini\" target=\"_blank\" rel=\"noopener noreferrer\">bogini</a> <a href=\"https://pl.wikipedia.org/wiki/Sztuka\" target=\"_blank\" rel=\"noopener noreferrer\">sztuki</a> i <a href=\"https://pl.wikipedia.org/wiki/Rzemios%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">rzemiosła</a>, <a href=\"https://pl.wikipedia.org/wiki/M%C4%85dro%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">mądrości</a>, <a href=\"https://pl.wikipedia.org/wiki/Nauka\" target=\"_blank\" rel=\"noopener noreferrer\">nauki</a> i <a href=\"https://pl.wikipedia.org/wiki/Literatura\" target=\"_blank\" rel=\"noopener noreferrer\">literatury</a> oraz wojny słusznej. Jest to prawdopodobnie bogini pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Etruskowie\" target=\"_blank\" rel=\"noopener noreferrer\">etruskiego</a> (znana jest etruska bogini <a href=\"https://pl.wikipedia.org/wiki/Menrva\" target=\"_blank\" rel=\"noopener noreferrer\">Menrva</a>). Razem z <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowiszem</a> i <a href=\"https://pl.wikipedia.org/wiki/Junona\" target=\"_blank\" rel=\"noopener noreferrer\">Junoną</a> tworzyła <a href=\"https://pl.wikipedia.org/wiki/Tr%C3%B3jca_Kapitoli%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Trójcę Kapitolińską</a>.", "Mesua": "Drzewa z gatunku <i>Mesua ferrea</i> traktowane są jako święte w Indiach i w <a href=\"https://pl.wikipedia.org/wiki/Wietnam\" target=\"_blank\" rel=\"noopener noreferrer\">Wietnamie</a>, gdzie sadzone są przy świątyniach. Jest to jedno z tzw. <a href=\"https://pl.wikipedia.org/wiki/Drzewo_%C5%BCelazne\" target=\"_blank\" rel=\"noopener noreferrer\">drzew żelaznych</a> – jest tak twarde i ciężkie, że nie nadaje się do obróbki siekierami, lecz wyłącznie maszynowej. Wykorzystywane jest do wyrobu słupów, podkładów kolejowych i na <a href=\"https://pl.wikipedia.org/wiki/Fornir\" target=\"_blank\" rel=\"noopener noreferrer\">fornir</a>, dawniej wykonywano z niego <a href=\"https://pl.wikipedia.org/wiki/W%C5%82%C3%B3cznia\" target=\"_blank\" rel=\"noopener noreferrer\">włócznie</a>. Pachnące kwiaty wykorzystywane są w lecznictwie, kosmetyce (w tym w przemyśle perfumeryjnym) oraz do aromatyzowania wypełnienia poduszek. Nasiona zawierają 79% oleju i stanowią główne źródło tego surowca dla ludu <a href=\"https://pl.wikipedia.org/wiki/Dai_(mniejszo%C5%9B%C4%87_narodowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Dai</a>. Ze względu na znaczenie użytkowe i ozdobne kwiaty gatunek <i>M. ferrea</i> jest popularnie uprawiany, zwłaszcza w Indiach i na <a href=\"https://pl.wikipedia.org/wiki/Jawa\" target=\"_blank\" rel=\"noopener noreferrer\">Jawie</a>.", "Makeda": "<b>Makeda</b> – pierwsza znana królowa <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Saba\" target=\"_blank\" rel=\"noopener noreferrer\">Saby</a>. Makeda to imię wywodzące się z tradycji <a href=\"https://pl.wikipedia.org/wiki/Etiopia\" target=\"_blank\" rel=\"noopener noreferrer\">etiopskiej</a>; w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskich</a> przekazach nazywana była Bilkis (<b>بلقيس</b> <i>Bilqīs</i>). Inne wersje jej imienia to Nikaule oraz Nicaula.", "Miłorada": "<b>Miłorada</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię żeńskie</a> złożone z członów Mił- (\"miła\", \"miłująca\") i -rada (\"być zadowolonym, chętnym, cieszyć się\" lub radzić - \"troszczyć się, dbać o coś\"). Męski odpowiednik: <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>.", "Morela": "<b>Morela</b> (<i>Armeniaca</i> Scop. ≡ <i>Prunus</i> subgen. <i>Prunus</i> sect. <i>Armeniaca</i>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a>, podrodzaj lub <a href=\"https://pl.wikipedia.org/wiki/Sekcja_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">sekcja</a> (w zależności od ujęcia klasyfikacyjnego) roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3%C5%BCowate\" target=\"_blank\" rel=\"noopener noreferrer\">różowatych</a>. Ze względu na zagnieżdżenie w obrębie rodzaju <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aliwa\" target=\"_blank\" rel=\"noopener noreferrer\">śliwa</a> <i>Prunus</i> zwykle wyróżniany w randze sekcji, co oznacza, że gatunki zaliczane są do rodzaju <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aliwa\" target=\"_blank\" rel=\"noopener noreferrer\">śliwa</a> (<i>Prunus</i>).", "Manea": "<b>Manea</b>, <i>Mannea</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Patronka tego imienia, św. Manea, jest wspominana razem ze swoim mężem, św. <a href=\"https://pl.wikipedia.org/wiki/Marcelin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Marcelinem</a>, trybunem, oraz z synami – św. <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Janem</a>, <a href=\"https://pl.wikipedia.org/wiki/Piotr_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Piotrem</a> i <a href=\"https://pl.wikipedia.org/wiki/Serapion\" target=\"_blank\" rel=\"noopener noreferrer\">Serapionem</a>.", "Machiko": "<b>Machiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まちこ, マチコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Makaria": "<b>Makaria</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa <i>makários</i> oznaczającego „szczęśliwy”. Patronką tego imienia jest św. Makaria, wspominana razem ze św. <a href=\"https://pl.wikipedia.org/wiki/Maksyma_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymą</a> i św. <a href=\"https://pl.wikipedia.org/wiki/January\" target=\"_blank\" rel=\"noopener noreferrer\">Januarym</a>.", "Mitsuki": "<b>Mitsuki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みつき, ミツキ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Mojra": "W różnych literackich przekazach wywodzono odmienne ich pochodzenie. U <a href=\"https://pl.wikipedia.org/wiki/Homer\" target=\"_blank\" rel=\"noopener noreferrer\">Homera</a> jest jedna Mojra, natomiast według <i><a href=\"https://pl.wikipedia.org/wiki/Theogonia\" target=\"_blank\" rel=\"noopener noreferrer\">Theogonii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Hezjod\" target=\"_blank\" rel=\"noopener noreferrer\">Hezjoda</a> były one trzema córkami <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a> i <a href=\"https://pl.wikipedia.org/wiki/Temida_(tytanida)\" target=\"_blank\" rel=\"noopener noreferrer\">Temidy</a>, noszącymi imiona: <a href=\"https://pl.wikipedia.org/wiki/Kloto\" target=\"_blank\" rel=\"noopener noreferrer\">Kloto</a> („Prządka” nici żywota), <a href=\"https://pl.wikipedia.org/wiki/Lachesis\" target=\"_blank\" rel=\"noopener noreferrer\">Lachesis</a> („Udzielająca”, która tej nici strzeże) i <a href=\"https://pl.wikipedia.org/wiki/Atropos\" target=\"_blank\" rel=\"noopener noreferrer\">Atropos</a> („Nieodwracalna”, która ją przecina). Według innych źródeł były one córkami Nocy i <a href=\"https://pl.wikipedia.org/wiki/Ereb\" target=\"_blank\" rel=\"noopener noreferrer\">Erebu</a> lub <a href=\"https://pl.wikipedia.org/wiki/Kronos\" target=\"_blank\" rel=\"noopener noreferrer\">Kronosa</a>, albo <a href=\"https://pl.wikipedia.org/wiki/Gaja_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Gai</a> i <a href=\"https://pl.wikipedia.org/wiki/Okeanos\" target=\"_blank\" rel=\"noopener noreferrer\">Okeanosa</a>. Symbolizowały <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytna_Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">starogreckie</a> pojęcia <a href=\"https://pl.wikipedia.org/wiki/Filozofia\" target=\"_blank\" rel=\"noopener noreferrer\">filozoficzno</a>-mitologiczne dotyczące losu ludzkiego i porządku świata. Ich siostrami były <a href=\"https://pl.wikipedia.org/wiki/Hory\" target=\"_blank\" rel=\"noopener noreferrer\">Hory</a> i <a href=\"https://pl.wikipedia.org/wiki/Charyty\" target=\"_blank\" rel=\"noopener noreferrer\">Charyty</a>. Były boginiami życia i śmierci oraz znały przyszłość ludzi i bogów. Jako jedyne nie podlegały też władzy <a href=\"https://pl.wikipedia.org/wiki/Bogowie_olimpijscy\" target=\"_blank\" rel=\"noopener noreferrer\">bogów olimpijskich</a>.", "Minami": "<b>Minami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みなみ, ミナミ, 南) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone częściej przez kobiety niż przez mężczyzn. Jest używane jako imię, nazwisko lub nazwa miejsca.", "Marzana": "Znaczenie użytkowe mają zwłaszcza ci przedstawiciele rodzaju, z których korzeni pozyskuje się czerwony barwnik. W Europie jest to <a href=\"https://pl.wikipedia.org/wiki/Marzana_barwierska\" target=\"_blank\" rel=\"noopener noreferrer\">marzana barwierska</a> <i>R. tinctoria</i>, a w <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indiach</a> – marzana sercolistna <i>R. cordifolia</i>. Jako roślina lecznicza wykorzystywana jest zwłaszcza <i>R. peregrina</i>.", "Motoko": "<b>Motoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;もとこ, モトコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Majola": "<b>Majola</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od słowa oznaczającego \"maj\". Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Majol\" target=\"_blank\" rel=\"noopener noreferrer\">Majol</a>, opat <a href=\"https://pl.wikipedia.org/wiki/Cluny\" target=\"_blank\" rel=\"noopener noreferrer\">Cluny</a> (<a href=\"https://pl.wikipedia.org/wiki/X_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">X wiek</a>).", "Maksymina": "<b>Maksymina</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Maksymin\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymin</a> o pochodzeniu łacińskim.", "Mingjia": "<b>Szkoła nazw</b> (<i>logiści</i>, <i>dialektycy</i>, <i>sofiści</i>) – jedna ze starożytnych <a href=\"https://pl.wikipedia.org/wiki/Filozofia_chi%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">chińskich szkół filozoficznych</a>, rozwijająca się w <a href=\"https://pl.wikipedia.org/wiki/Okres_Walcz%C4%85cych_Kr%C3%B3lestw\" target=\"_blank\" rel=\"noopener noreferrer\">Okresie Walczących Królestw</a>, znanym także jako okres „<a href=\"https://pl.wikipedia.org/wiki/Sto_szk%C3%B3%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Stu szkół</a>”. Jej przedstawiciele poświęcali się badaniom nad znaczeniami pojęć, ich systematyką i dociekaniem sposobów poprawnego rozumowania. Mimo iż szkoła nazw była niewielka i nie wywarła dużego wpływu na późniejsze systemy filozoficzne Państwa Środka, jest warta uwagi ze względu na fakt, iż była jedyną chińską szkołą myślową zajmującą się <a href=\"https://pl.wikipedia.org/wiki/Logika\" target=\"_blank\" rel=\"noopener noreferrer\">logiką</a> i problemami <a href=\"https://pl.wikipedia.org/wiki/Epistemologia\" target=\"_blank\" rel=\"noopener noreferrer\">epistemologicznymi</a>. Za twórcę szkoły uchodzi żyjący w VI wieku p.n.e. prawnik <a href=\"https://pl.wikipedia.org/wiki/Deng_Xi\" target=\"_blank\" rel=\"noopener noreferrer\">Deng Xi</a>.", "Minako": "<b>Minako</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みなこ, ミナコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Macha": "Wraz z <a href=\"https://pl.wikipedia.org/wiki/Anann\" target=\"_blank\" rel=\"noopener noreferrer\">Anann</a> i <a href=\"https://pl.wikipedia.org/wiki/Badb\" target=\"_blank\" rel=\"noopener noreferrer\">Badb</a> tworzyła triumwirat bogiń wojny, należąc do grupy irlandzkich bóstw wojny. Karmiła się głowami swoich wrogów, lecz podobno często leczyła rannych. Uważano, że była <a href=\"https://pl.wikipedia.org/wiki/Monarcha\" target=\"_blank\" rel=\"noopener noreferrer\">królową</a> <a href=\"https://pl.wikipedia.org/wiki/Ulster\" target=\"_blank\" rel=\"noopener noreferrer\">Ulsteru</a>, której stolicę na cześć jej imienia nazwano Emain Macha. Ona i inne wcielenia Morrigan (Badb i <a href=\"https://pl.wikipedia.org/wiki/Nemain\" target=\"_blank\" rel=\"noopener noreferrer\">Nemhain</a>) wspomagały lud <a href=\"https://pl.wikipedia.org/wiki/Tuatha_de_Danaan\" target=\"_blank\" rel=\"noopener noreferrer\">Tuatha de Danaan</a> w walce z plemieniem <a href=\"https://pl.wikipedia.org/wiki/Fir_Bolg\" target=\"_blank\" rel=\"noopener noreferrer\">Firbolgów</a>.", "Mildreda": "<b>Mildreda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, składające się z członów <i>mil- //mild-</i> (\"miłosierna, szczera, dobra\") i <i>-red // -rad</i> (\"pomoc, rada, ratunek\").", "Maria Adelajda": "Po swej abdykacji Maria Adelajda wstąpiła do <a href=\"https://pl.wikipedia.org/wiki/Zakon\" target=\"_blank\" rel=\"noopener noreferrer\">zakonu</a> <a href=\"https://pl.wikipedia.org/wiki/Karmelitanki\" target=\"_blank\" rel=\"noopener noreferrer\">karmelitanek</a>, przyjmując imię <i>Marii Ubogich</i>. Zmarła na zamku w Hohenburgu (w <a href=\"https://pl.wikipedia.org/wiki/Bawaria\" target=\"_blank\" rel=\"noopener noreferrer\">Bawarii</a>).", "Meliana": "Imiona wszystkich Majarów pochodzą z quenyi.", "Mama": "W <a href=\"https://pl.wikipedia.org/wiki/Prawo_rodzinne\" target=\"_blank\" rel=\"noopener noreferrer\">prawie rodzinnym</a> matka jest <a href=\"https://pl.wikipedia.org/wiki/Wst%C4%99pny\" target=\"_blank\" rel=\"noopener noreferrer\">wstępną</a> <a href=\"https://pl.wikipedia.org/wiki/Pokrewie%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">krewną</a> <a href=\"https://pl.wikipedia.org/wiki/Stopie%C5%84_pokrewie%C5%84stwa\" target=\"_blank\" rel=\"noopener noreferrer\">pierwszego stopnia</a> w <a href=\"https://pl.wikipedia.org/wiki/Stopie%C5%84_pokrewie%C5%84stwa\" target=\"_blank\" rel=\"noopener noreferrer\">linii prostej</a>, od którego dziecko <a href=\"https://pl.wikipedia.org/wiki/Pochodzenie_dziecka\" target=\"_blank\" rel=\"noopener noreferrer\">pochodzi</a> bezpośrednio. W <a href=\"https://pl.wikipedia.org/wiki/Genealogia\" target=\"_blank\" rel=\"noopener noreferrer\">genealogii</a> matkę i dziecko łączy <a href=\"https://pl.wikipedia.org/wiki/Filiacja\" target=\"_blank\" rel=\"noopener noreferrer\">filiacja</a>, a matkę z <a href=\"https://pl.wikipedia.org/wiki/Ojciec\" target=\"_blank\" rel=\"noopener noreferrer\">ojcem</a> łączy <a href=\"https://pl.wikipedia.org/wiki/Koicja\" target=\"_blank\" rel=\"noopener noreferrer\">koicja</a>.", "Myria": "<b>Myria</b> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> (<i>ma</i> = 10&#160;000) i <b>myrio</b> (<i>mo</i> = 1/10&#160;000) – przedrostki używane w starszych wersjach <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_SI\" target=\"_blank\" rel=\"noopener noreferrer\">systemu metrycznego</a>, nie będące częścią <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_SI\" target=\"_blank\" rel=\"noopener noreferrer\">układu SI</a>. Przedrostki te pochodzą z greckiego μύριοι (mýrioi), oznaczającego zarówno „dziesięć tysięcy” jak i „nieskończenie wielka liczba” (podobne znaczenie ma także 10&#160;000 w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">kulturze chińskiej</a>).", "Mion": "<b>Miony</b> – nietrwałe <a href=\"https://pl.wikipedia.org/wiki/Cz%C4%85stka_elementarna\" target=\"_blank\" rel=\"noopener noreferrer\">cząstki elementarne</a>, należące do <a href=\"https://pl.wikipedia.org/wiki/Lepton_(mechanika_kwantowa)\" target=\"_blank\" rel=\"noopener noreferrer\">leptonów</a>. Występują w dwóch stanach ładunkowych (będących wzajemnie <a href=\"https://pl.wikipedia.org/wiki/Antymateria\" target=\"_blank\" rel=\"noopener noreferrer\">antycząstkami</a>) μ i μ. Oznacza się je <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskułą</a> greckiej litery <a href=\"https://pl.wikipedia.org/wiki/My_(litera)\" target=\"_blank\" rel=\"noopener noreferrer\">my</a>.", "Mitsuko": "<b>Mitsuko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みつこ, ミツコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Metoda": "<b>Metoda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Metody\" target=\"_blank\" rel=\"noopener noreferrer\">Metody</a>. Wywodzi się od słowa <i>methodos</i> - \"kroczący właściwą drogą\".", "Moral": "<b>Moral</b> właściwie <b>Kamil Michalak</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/24_sierpnia\" target=\"_blank\" rel=\"noopener noreferrer\">24 sierpnia</a> <a href=\"https://pl.wikipedia.org/wiki/1985\" target=\"_blank\" rel=\"noopener noreferrer\">1985</a> w <a href=\"https://pl.wikipedia.org/wiki/D%C4%85browa_G%C3%B3rnicza\" target=\"_blank\" rel=\"noopener noreferrer\">Dąbrowie Górniczej</a>) – polski <a href=\"https://pl.wikipedia.org/wiki/Raper\" target=\"_blank\" rel=\"noopener noreferrer\">raper</a> i <a href=\"https://pl.wikipedia.org/wiki/Producent_muzyczny\" target=\"_blank\" rel=\"noopener noreferrer\">producent muzyczny</a>. Kamil Michalak znany jest przede wszystkim z występów w duecie wraz raperem <a href=\"https://pl.wikipedia.org/wiki/Gano_(raper)\" target=\"_blank\" rel=\"noopener noreferrer\">Gano</a> wraz z którym nagrał dwie płyty. Prowadzi także solową działalność artystyczną. Współtworzy także formację All Star-Team i kolektyw Gopside.", "Mudita": "<b>Mudita</b> – jest <a href=\"https://pl.wikipedia.org/wiki/Buddyzm\" target=\"_blank\" rel=\"noopener noreferrer\">buddyjskim</a> określeniem pochodzącym z języka <a href=\"https://pl.wikipedia.org/wiki/P%C4%81li\" target=\"_blank\" rel=\"noopener noreferrer\">pali</a> i <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskrytu</a>, które oznacza <a href=\"https://pl.wikipedia.org/wiki/Rado%C5%9B%C4%87_(emocja)\" target=\"_blank\" rel=\"noopener noreferrer\">radość</a> z powodu pomyślności innych, <b>empatyczną radość</b>, <b>radosne współczucie</b>, <b>altruistyczną radość</b>, <b>współradość</b>. Można spotkać się też z określeniem <b>najwyższa radość</b>. Mudita jest czasem przedstawiana jako przeciwieństwo przyjemności czerpanej z czyjegoś nieszczęścia (w języku niemieckim istnieje określający to termin <a href=\"https://pl.wikipedia.org/wiki/Schadenfreude\" target=\"_blank\" rel=\"noopener noreferrer\">Schadenfreude</a>). Mudita jest trzecią z <a href=\"https://pl.wikipedia.org/wiki/Cztery_Niezmierzono%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">Czterech Niezmierzoności</a>.", "Merceda": "Od imienia <a href=\"https://pl.wikipedia.org/wiki/Merc%C3%A9d%C3%A8s_Jellinek\" target=\"_blank\" rel=\"noopener noreferrer\">Mercédès Jellinek</a>, córki <a href=\"https://pl.wikipedia.org/wiki/Emil_Jellinek\" target=\"_blank\" rel=\"noopener noreferrer\">Emila Jellinka</a>, generalnego przedstawiciela firmy <a href=\"https://pl.wikipedia.org/wiki/Daimler-Motoren-Gesellschaft\" target=\"_blank\" rel=\"noopener noreferrer\">Daimler</a>, pochodzi nazwa marki samochodów <a href=\"https://pl.wikipedia.org/wiki/Mercedes-Benz\" target=\"_blank\" rel=\"noopener noreferrer\">Mercedes</a>. W Polsce bardzo rzadko używane ze względu na spółgłoskowy wygłos oraz fakt, iż wyraz ten bardziej znany jest jako marka samochodu (i powszechnie postrzegany jako posiadający rodzaj męski), niż imię żeńskie.", "Metta": "<b>Mettā</b> (<a href=\"https://pl.wikipedia.org/wiki/P%C4%81li\" target=\"_blank\" rel=\"noopener noreferrer\">Pāli</a>) lub <b>Maitrī</b> (<a href=\"https://pl.wikipedia.org/wiki/Skt.\" target=\"_blank\" rel=\"noopener noreferrer\">Skt.</a>) – oznacza bezwarunkową i nieprzywiązaną do konkretnych obiektów <b>miłującą dobroć</b>, <b>kochającą życzliwość</b>, miłowanie. Jest ona częścią dziesięciu <a href=\"https://pl.wikipedia.org/wiki/Paramita\" target=\"_blank\" rel=\"noopener noreferrer\">paramit</a> <a href=\"https://pl.wikipedia.org/wiki/Buddyzm\" target=\"_blank\" rel=\"noopener noreferrer\">buddyjskiej</a> szkoły <a href=\"https://pl.wikipedia.org/wiki/Theravada\" target=\"_blank\" rel=\"noopener noreferrer\">theravada</a>, a także pierwszą z <a href=\"https://pl.wikipedia.org/wiki/Cztery_Niezmierzono%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">Czterech Niezmierzoności</a>. Praktyka <b>mettā bhāvanā</b> (<i>pielęgnowanie</i> <b>mettā</b>) jest popularną formą <a href=\"https://pl.wikipedia.org/wiki/Medytacja\" target=\"_blank\" rel=\"noopener noreferrer\">medytacji</a> w <a href=\"https://pl.wikipedia.org/wiki/Buddyzm\" target=\"_blank\" rel=\"noopener noreferrer\">buddyzmie</a>, praktykowaną ze <a href=\"https://pl.wikipedia.org/wiki/Anapana\" target=\"_blank\" rel=\"noopener noreferrer\">świadomym oddychaniem</a>, która polega na koncentracji ukierunkowanej na rozwijanie <a href=\"https://pl.wikipedia.org/wiki/Karuna\" target=\"_blank\" rel=\"noopener noreferrer\">współczucia</a>.", "Maksencja": "<b>Maksencja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od imienia <i>Maxentius</i>, wywodzącego się od słowa <i>maximus</i> \"największy, najwspanialszy\". Patronką tego imienia jest św. Maksencja z <a href=\"https://pl.wikipedia.org/wiki/Beauvais\" target=\"_blank\" rel=\"noopener noreferrer\">Beauvais</a>, <a href=\"https://pl.wikipedia.org/wiki/Szkocja\" target=\"_blank\" rel=\"noopener noreferrer\">Szkotka</a> z pochodzenia, oraz św. <a href=\"https://pl.wikipedia.org/wiki/Maksencja_z_Trydentu\" target=\"_blank\" rel=\"noopener noreferrer\">Maksencja z Trydentu</a>, matka <a href=\"https://pl.wikipedia.org/wiki/Wigiliusz_z_Trydentu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Wigiliusza</a>.", "Mona Liza": "<b>Mona Lisa</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> <i>Gioconda</i>) – obraz olejny namalowany na <a href=\"https://pl.wikipedia.org/wiki/Topola\" target=\"_blank\" rel=\"noopener noreferrer\">topolowej</a> desce przez <a href=\"https://pl.wikipedia.org/wiki/Leonardo_da_Vinci\" target=\"_blank\" rel=\"noopener noreferrer\">Leonarda da Vinci</a>, artystę <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Renesans\" target=\"_blank\" rel=\"noopener noreferrer\">renesansu</a>. Jego nazwa pochodzi od słowa <i>mona,</i> które w dialekcie toskańskim jest skrótem od tytułu <i>ma donna</i> („moja pani”), oraz imienia domniemanego tematu portretu. We <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszp.</a> znany jest jako <i>La Gioconda,</i> a we <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a> <i>La Joconde</i> – od nazwy rodu kupca, który zamówił to dzieło.", "Mignon": "Od późnego <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecza</a> określenie to oznaczało osobistego przyjaciela <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3l\" target=\"_blank\" rel=\"noopener noreferrer\">króla</a>, który nie musiał zawsze przestrzegać w stosunku do niego <a href=\"https://pl.wikipedia.org/wiki/Kurtuazja\" target=\"_blank\" rel=\"noopener noreferrer\">kurtuazji</a>, np. mógł ubierać się tak samo okazale jak król."};
